import React from "react";
import { Helmet } from "react-helmet-async";

interface SEOHelmetProps {
  title: string;
  description?: string;
  image?: string;
  canonical?: string;
  noindex?: boolean;
  schema?: object;
}

const DEFAULT_DESCRIPTION =
  "Great Limbus Library ŌĆö ą▒ą░ąĘą░ ą┤ą░ąĮąĮčŗčģ ą┐ąŠ Limbus Company: tier-ą╗ąĖčüčéčŗ, ID, EGO, čüčéą░čéčāčüčŗ, ą│ą░ą╣ą┤čŗ ąĖ Mirror Dungeon.";

const DEFAULT_IMAGE = "https://gll-fun.com/prewie/logo.png";
const SITE_NAME = "Great Limbus Library";
const SITE_URL = "https://gll-fun.com";

export const SEOHelmet: React.FC<SEOHelmetProps> = ({
  title,
  description,
  image = DEFAULT_IMAGE,
  canonical,
  noindex = false,
  schema,
}) => {
  const safeDescription = description?.trim() || DEFAULT_DESCRIPTION;
  const url =
    canonical ||
    (typeof window !== "undefined" ? window.location.href : SITE_URL);

  return (
    <Helmet>
      {/* BASIC */}
      <title>{title}</title>
      <meta name="description" content={safeDescription} />

      {/* ROBOTS */}
      <meta
        name="robots"
        content={noindex ? "noindex, nofollow" : "index, follow"}
      />

      {/* CANONICAL */}
      <link rel="canonical" href={url} />

      {/* OPEN GRAPH */}
      <meta property="og:type" content="website" />
      <meta property="og:site_name" content={SITE_NAME} />
      <meta property="og:title" content={title} />
      <meta property="og:description" content={safeDescription} />
      <meta property="og:image" content={image} />
      <meta property="og:url" content={url} />

      {/* TWITTER */}
      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:title" content={title} />
      <meta name="twitter:description" content={safeDescription} />
      <meta name="twitter:image" content={image} />

      {/* SCHEMA */}
      {schema && (
        <script type="application/ld+json">
          {JSON.stringify(schema)}
        </script>
      )}
    </Helmet>
  );
};
