import React, { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import "./LoadingAnimation.css";

type TLoadingAnimationProps = {
  failureCount?: number;
};

export const LoadingAnimation: React.FC<TLoadingAnimationProps> = ({ failureCount = 0 }) => {
  const { t } = useTranslation();
  const [delayText, setDelayText] = useState("");
  const [isTooltipVisible, setIsTooltipVisible] = useState(false);

  useEffect(() => {
    let timeoutId: NodeJS.Timeout;

    if (failureCount > 2) {
      const generateRandomDelayText = () => {
        const randomDelay = Math.floor(Math.random() * 14) + 1; // ąōąĄąĮąĄčĆąĖčĆčāąĄą╝ čüą╗čāčćą░ą╣ąĮąŠąĄ čćąĖčüą╗ąŠ ąŠčé 1 ą┤ąŠ 14
        setDelayText(t(`LoadingAnimation.delay${randomDelay}`)); // ąŻčüčéą░ąĮąŠą▓ąĖčéčī čéąĄą║čüčé ąĘą░ą┤ąĄčĆąČą║ąĖ

        timeoutId = setTimeout(() => {
          generateRandomDelayText(); // ą×ą▒ąĮąŠą▓ą╗čÅąĄą╝ čéąĄą║čüčé ąĘą░ą┤ąĄčĆąČą║ąĖ čćąĄčĆąĄąĘ 10 čüąĄą║čāąĮą┤
        }, 10000); // ąóą░ą╣ą╝ą░čāčé ąĮą░ 10 čüąĄą║čāąĮą┤
      };

      generateRandomDelayText();

      return () => {
        clearTimeout(timeoutId);
      };
    }
  }, [failureCount, t]);

  const handleMouseOver = () => {
    setIsTooltipVisible(true);
  };

  const handleMouseOut = () => {
    setIsTooltipVisible(false);
  };

  return (
    <div className="loading-container">
      <div className="image-container">
        <img 
          src="/images/general/loading.webp" 
          alt="Loading Animation" 
          className="loading-image" 
          onMouseOver={handleMouseOver} 
          onMouseOut={handleMouseOut} 
        />
        {isTooltipVisible && (
          <div className="tooltip">
            {t("LoadingAnimation.tooltip")}
          </div>
        )}
      </div>
      <div className="loading">
        {t("LoadingAnimation.text")}
        <span className="dot">.</span>
        <span className="dot">.</span>
        <span className="dot">.</span>
      </div>
      <span className="delay-info">{failureCount > 2 && delayText}</span>
    </div>
  );
};
