import React from 'react';
import "./TooltipMobile.css";
import { SkillCoinDescription } from "../guides/text-formatter/SkillCoinDescription";
import { useDispatch } from 'react-redux';
import { setMobileModalTrigger } from '../../store/reducers/mobile-modal-reducer';

interface ITooltipMobileProps {
    image?: React.ReactNode;
    header?: string;
    text: string;
    // ą£ą░čüčüąĖą▓ ą┐čĆąĄą┤čŗą┤čāčēąĖčģ čüąŠčüčéąŠčÅąĮąĖą╣ čéčāą╗čéąĖą┐ą░
    history?: React.ReactNode[]; 
}

export const TooltipMobile: React.FC<ITooltipMobileProps> = ({ image, text, header, history = [] }) => {
    const dispatch = useDispatch();

    // ążčāąĮą║čåąĖčÅ ą▓ąŠąĘą▓čĆą░čéą░ ąĮą░ąĘą░ą┤
    const goBack = (e: React.MouseEvent) => {
        e.stopPropagation();
        if (history.length === 0) return;

        // ąÜąŠą┐ąĖčĆčāąĄą╝ ąĖčüčéąŠčĆąĖčÄ
        const newHistory = [...history];
        // ąöąŠčüčéą░ąĄą╝ ą┐ąŠčüą╗ąĄą┤ąĮąĄąĄ čüąŠčģčĆą░ąĮąĄąĮąĮąŠąĄ ąŠą║ąĮąŠ
        const previousModal = newHistory.pop(); 
        
        if (previousModal) {
            // ąÆą░ąČąĮąŠ: ą╝čŗ ą┐čĆąĄą┤ą┐ąŠą╗ą░ą│ą░ąĄą╝, čćčéąŠ ą▓ čüąŠčģčĆą░ąĮąĄąĮąĮąŠą╝ ąŠą║ąĮąĄ čāąČąĄ ą╗ąĄąČąĖčé ą░ą║čéčāą░ą╗čīąĮą░čÅ ąĖčüčéąŠčĆąĖčÅ
            setMobileModalTrigger(dispatch, previousModal);
        }
    };

    // ą×ą▒ąĄčĆčéą║ą░ ą┤ą╗čÅ SkillCoinDescription, čćčéąŠą▒čŗ ą┐čĆąŠą║ąĖą┤čŗą▓ą░čéčī ąĖčüčéąŠčĆąĖčÄ ą┤ą░ą╗čīčłąĄ
    // ą£čŗ ą┐ąĄčĆąĄą┤ą░ąĄą╝ čéąĄą║čāčēąĄąĄ ąŠą║ąĮąŠ ą▓ ąĖčüčéąŠčĆąĖčÄ ą┤ą╗čÅ čüą╗ąĄą┤čāčÄčēąĄą│ąŠ čāčĆąŠą▓ąĮčÅ
    const currentAsHistoryItem = (
        <TooltipMobile image={image} header={header} text={text} history={history} />
    );
    const nextHistory = [...history, currentAsHistoryItem];

    return (
        <div className='TooltipMobile'>
            {/* ąÜąĮąŠą┐ą║ą░ "ąØą░ąĘą░ą┤", ąĄčüą╗ąĖ ąĄčüčéčī ąĖčüčéąŠčĆąĖčÅ */}
            {history.length > 0 && (
                <button className="TooltipMobile-back" onClick={goBack}>
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                        <path d="M19 12H5M12 19l-7-7 7-7"/>
                    </svg>
                </button>
            )}

            {(!!header || !!image) && (
                <>
                    <span className='TooltipMobile-header'>
                        {header ? header : ""}
                        {image ? image : <></>}
                    </span>
                    <hr />
                </>
            )}
            
            <div className='TooltipMobile-info'>
                {/* ą¤ąĄčĆąĄą┤ą░ąĄą╝ ąĖčüčéąŠčĆąĖčÄ ą▓ ą┐ą░čĆčüąĄčĆ, čćčéąŠą▒čŗ ą┐čĆąĖ ą║ą╗ąĖą║ąĄ ąĮą░ ąĮąŠą▓čŗą╣ čüčéą░čéčāčü ąŠąĮ ąĘąĮą░ą╗, ą║čāą┤ą░ ą▓ąŠąĘą▓čĆą░čēą░čéčīčüčÅ */}
                <SkillCoinDescription description={text} historyContext={nextHistory} />
            </div>
        </div>
    );
};