import { useState, useEffect } from "react";
import { useQueryClient } from "react-query";
import "./TournamentGrid.css";

interface TournamentGridInterface {
    name: string;
    win1?: string; // 1/4 čäąĖąĮą░ą╗ą░: 0 - ąĮąĄ ąĮą░čćą░ą╗ąŠčüčī, 1 - ą┐čĆąŠąĖą│čĆą░ą╗, 2 - ą▓čŗąĖą│čĆą░ą╗
    date1: string; // ą┤ą░čéą░ 1/4 čäąĖąĮą░ą╗ą░
    win2?: string; // 1/2 čäąĖąĮą░ą╗ą░: 0 - ąĮąĄ ąĮą░čćą░ą╗ąŠčüčī, 1 - ą┐čĆąŠąĖą│čĆą░ą╗, 2 - ą▓čŗąĖą│čĆą░ą╗
    date2: string; // ą┤ą░čéą░ 1/2 čäąĖąĮą░ą╗ą░
    win3?: string; // ążąĖąĮą░ą╗: 0 - ąĮąĄ ąĮą░čćą░ą╗ąŠčüčī, 1 - ą┐čĆąŠąĖą│čĆą░ą╗, 2 - ą▓čŗąĖą│čĆą░ą╗
    date3: string; // ą┤ą░čéą░ čäąĖąĮą░ą╗ą░
    win4?: string; // ą¤ąŠą▒ąĄą┤ąĖčéąĄą╗čī: 0 - ąĮąĄ ąĮą░čćą░ą╗ąŠčüčī, 1 - ą┐čĆąŠąĖą│čĆą░ą╗, 2 - ą▓čŗąĖą│čĆą░ą╗
}

const TournamentGrid = () => {
    const queryClient = useQueryClient();
    const tournaments = queryClient.getQueryData('turnamnetgrid') as TournamentGridInterface[];
    
    // ąöąĄą▒ą░ą│-ą╗ąŠą│ąĖčĆąŠą▓ą░ąĮąĖąĄ ą┐ąŠą╗čāčćąĄąĮąĮčŗčģ ą┤ą░ąĮąĮčŗčģ
    useEffect(() => {
        console.log('ą¤ąŠą╗čāčćąĄąĮčŗ ą┤ą░ąĮąĮčŗąĄ čéčāčĆąĮąĖčĆą░:', tournaments);
        
        if (tournaments) {
            console.log('ąÜąŠą╗ąĖčćąĄčüčéą▓ąŠ ąĘą░ą┐ąĖčüąĄą╣:', tournaments.length);
            tournaments.forEach((player, index) => {
                console.log(`ąśą│čĆąŠą║ ${index + 1}:`, `ąśą╝čÅ: ${player.name}`, 
                    `ąöą░čéą░1: ${player.date1}`, `ąöą░čéą░2: ${player.date2}`, `ąöą░čéą░3: ${player.date3}`,
                    `Win1: ${player.win1}`, `Win2: ${player.win2}`, `Win3: ${player.win3}`, `Win4: ${player.win4}`);
            });
        }
    }, [tournaments]);
    
    // ąōčĆčāą┐ą┐ąĖčĆčāąĄą╝ ąĖą│čĆąŠą║ąŠą▓ ą┐ąŠ ą┤ą░čéą░ą╝ 1/4 čäąĖąĮą░ą╗ą░
    const quarterFinalGroups = tournaments?.reduce((acc: Record<string, TournamentGridInterface[]>, player) => {
        if (!player.name) {
            console.warn('ąØą░ą╣ą┤ąĄąĮ ąĖą│čĆąŠą║ ą▒ąĄąĘ ąĖą╝ąĄąĮąĖ:', player);
            return acc;
        }
        
        if (!acc[player.date1]) {
            acc[player.date1] = [];
        }
        
        acc[player.date1].push(player);
        return acc;
    }, {}) || {};
    
    // ąĪąŠąĘą┤ą░ąĄą╝ ą╝ą░čüčüąĖą▓ ą╝ą░čéčćąĄą╣ 1/4 čäąĖąĮą░ą╗ą░ (ą║ą░ąČą┤čŗą╣ ą╝ą░čéčć - ą┐ą░čĆą░ ąĖą│čĆąŠą║ąŠą▓ čü ąŠą┤ąĖąĮą░ą║ąŠą▓ąŠą╣ ą┤ą░čéąŠą╣ date1)
    const quarterFinalMatches: TournamentGridInterface[][] = Object.values(quarterFinalGroups).filter(group => group.length >= 1);
    
    // ą¤čĆąĄąŠą▒čĆą░ąĘčāąĄą╝ ą▓ ą┐ą╗ąŠčüą║ąĖą╣ ą╝ą░čüčüąĖą▓ ąĖą│čĆąŠą║ąŠą▓ ą┤ą╗čÅ čüąĄčéą║ąĖ, čüąŠčģčĆą░ąĮčÅčÅ ą┐ą░čĆčŗ
    const playersList: TournamentGridInterface[] = [];
    quarterFinalMatches.forEach(match => {
        playersList.push(match[0]);
        playersList.push(match[1] || { name: "", date1: "", date2: "", date3: "" });
    });
    
    // ąŚą░ą┐ąŠą╗ąĮčÅąĄą╝ ą┤ąŠ 8 ąĖą│čĆąŠą║ąŠą▓ (4 ą╝ą░čéčćą░), ąĄčüą╗ąĖ ąĮčāąČąĮąŠ
    while (playersList.length < 8) {
        playersList.push({ name: "", date1: "", date2: "", date3: "" });
    }
    
    // ążčāąĮą║čåąĖčÅ ą┤ą╗čÅ ąŠą┐čĆąĄą┤ąĄą╗ąĄąĮąĖčÅ ą┐ąŠą▒ąĄą┤ąĖčéąĄą╗ąĄą╣ ą║ą░ąČą┤ąŠą│ąŠ čĆą░čāąĮą┤ą░ ąĮą░ ąŠčüąĮąŠą▓ąĄ ą┤ą░ąĮąĮčŗčģ
    const calculateWinners = () => {
        const calculatedWinners: (number | null)[] = Array(7).fill(null);
        
        // 1/4 čäąĖąĮą░ą╗ą░ (ą╝ą░čéčćąĖ 0-3)
        for (let i = 0; i < 4; i++) {
            const player1Idx = i * 2;
            const player2Idx = i * 2 + 1;
            
            const player1 = playersList[player1Idx];
            const player2 = playersList[player2Idx];
            
            if (player1?.win1 === '2') {
                calculatedWinners[i] = player1Idx;
            } else if (player2?.win1 === '2') {
                calculatedWinners[i] = player2Idx;
            }
        }
        
        // 1/2 čäąĖąĮą░ą╗ą░ (ą╝ą░čéčćąĖ 4-5)
        for (let i = 4; i < 6; i++) {
            const prevMatch1 = i === 4 ? 0 : 2;
            const prevMatch2 = i === 4 ? 1 : 3;
            
            const winner1 = calculatedWinners[prevMatch1];
            const winner2 = calculatedWinners[prevMatch2];
            
            if (winner1 !== null && playersList[winner1]?.win2 === '2') {
                calculatedWinners[i] = winner1;
            } else if (winner2 !== null && playersList[winner2]?.win2 === '2') {
                calculatedWinners[i] = winner2;
            }
        }
        
        // ążąĖąĮą░ą╗ (ą╝ą░čéčć 6)
        const semiFinalWinner1 = calculatedWinners[4];
        const semiFinalWinner2 = calculatedWinners[5];
        
        if (semiFinalWinner1 !== null && playersList[semiFinalWinner1]?.win3 === '2') {
            calculatedWinners[6] = semiFinalWinner1;
        } else if (semiFinalWinner2 !== null && playersList[semiFinalWinner2]?.win3 === '2') {
            calculatedWinners[6] = semiFinalWinner2;
        }
        
        return calculatedWinners;
    };
    
    const [winners, setWinners] = useState<(number | null)[]>(calculateWinners());

    // ą×ą▒ąĮąŠą▓ą╗čÅąĄą╝ ą┐ąŠą▒ąĄą┤ąĖčéąĄą╗ąĄą╣ ą┐čĆąĖ ąĖąĘą╝ąĄąĮąĄąĮąĖąĖ ą┤ą░ąĮąĮčŗčģ
    useEffect(() => {
        setWinners(calculateWinners());
    }, [tournaments]);

    const getMatchPlayers = (matchIndex: number): [number | null, number | null] => {
        switch (matchIndex) {
            case 0: return [0, 1];
            case 1: return [2, 3];
            case 2: return [4, 5];
            case 3: return [6, 7];
            case 4: return [winners[0], winners[1]];
            case 5: return [winners[2], winners[3]];
            case 6: return [winners[4], winners[5]];
            default: return [null, null];
        }
    };

    const getPlayerName = (index: number | null) => {
        if (index === null) return "";
        const player = playersList[index];
        return player?.name || "";
    };

    // ążčāąĮą║čåąĖčÅ ą┤ą╗čÅ ą┐ąŠą╗čāčćąĄąĮąĖčÅ ą┤ą░čéčŗ ą╝ą░čéčćą░
    const getMatchDate = (matchIndex: number): string => {
        if (matchIndex < 4) {
            // ąöą╗čÅ 1/4 čäąĖąĮą░ą╗ą░ ą▒ąĄčĆąĄą╝ date1 ąĖąĘ ą╗čÄą▒ąŠą│ąŠ ąĖąĘ ąĖą│čĆąŠą║ąŠą▓
            const [player1Idx] = getMatchPlayers(matchIndex);
            if (player1Idx !== null) {
                return playersList[player1Idx]?.date1 || "";
            }
        } else if (matchIndex < 6) {
            // ąöą╗čÅ 1/2 čäąĖąĮą░ą╗ą░ ą▒ąĄčĆąĄą╝ date2 ąĖąĘ ą┐ąŠą▒ąĄą┤ąĖčéąĄą╗čÅ ą┐čĆąĄą┤čŗą┤čāčēąĄą│ąŠ čĆą░čāąĮą┤ą░
            const [player1Idx] = getMatchPlayers(matchIndex);
            if (player1Idx !== null) {
                return playersList[player1Idx]?.date2 || "";
            }
        } else {
            // ąöą╗čÅ čäąĖąĮą░ą╗ą░ ą▒ąĄčĆąĄą╝ date3 ąĖąĘ ą┐ąŠą▒ąĄą┤ąĖčéąĄą╗čÅ ą┐čĆąĄą┤čŗą┤čāčēąĄą│ąŠ čĆą░čāąĮą┤ą░
            const [player1Idx] = getMatchPlayers(matchIndex);
            if (player1Idx !== null) {
                return playersList[player1Idx]?.date3 || "";
            }
        }
        return "";
    };

    // ążčāąĮą║čåąĖčÅ ą┤ą╗čÅ ąŠą┐čĆąĄą┤ąĄą╗ąĄąĮąĖčÅ čüčéąĖą╗čÅ ąĖą│čĆąŠą║ą░ ą▓ ąĘą░ą▓ąĖčüąĖą╝ąŠčüčéąĖ ąŠčé čüčéą░čéčāčüą░
    const getPlayerStyle = (index: number | null, round: 'win1' | 'win2' | 'win3' | 'win4') => {
        if (index === null) return {};
        
        const player = playersList[index];
        if (!player) return {};
        
        const status = player[round];
        
        switch (status) {
            case '1': // ą¤čĆąŠąĖą│čĆą░ą╗
                return { textDecoration: 'line-through', color: '#999' };
            case '2': // ąÆčŗąĖą│čĆą░ą╗
                return { fontWeight: 'bold', color: '#a057e0' };
            default: // 0 ąĖą╗ąĖ ąĮąĄ ąŠą┐čĆąĄą┤ąĄą╗ąĄąĮ
                return {};
        }
    };

    return (
        <div className="tournament-grid">
            <div className="name"><h1>ąóčāčĆąĮąĖčĆąĮą░čÅ čüąĄčéą║ą░:</h1></div>
            
            
            <div className="round-titles">
                <h3>1/4 čäąĖąĮą░ą╗ą░</h3>
                <h3>1/2 čäąĖąĮą░ą╗ą░</h3>
                <h3>ążąĖąĮą░ą╗</h3>
                <h3>ą¤ąŠą▒ąĄą┤ąĖčéąĄą╗čī</h3>
            </div>
            
            <div className="grid-container">
                {/* Quarter Finals */}
                <div className="round quarter-finals">
                    {[0, 1, 2, 3].map((matchIndex) => {
                        const [player1Idx, player2Idx] = getMatchPlayers(matchIndex);
                        const player1 = getPlayerName(player1Idx);
                        const player2 = getPlayerName(player2Idx);
                        const matchDate = getMatchDate(matchIndex);
                        
                        return (
                            <div key={matchIndex} className="match">
                                <div className="match-date">{matchDate}</div>
                                <div 
                                    className="player" 
                                    style={getPlayerStyle(player1Idx, 'win1')}
                                >
                                    {player1}
                                </div>
                                <div 
                                    className="player" 
                                    style={getPlayerStyle(player2Idx, 'win1')}
                                >
                                    {player2}
                                </div>
                            </div>
                        );
                    })}
                </div>

                {/* Semi Finals */}
                <div className="round semi-finals">
                    {[4, 5].map((matchIndex) => {
                        const [player1Idx, player2Idx] = getMatchPlayers(matchIndex);
                        const player1 = getPlayerName(player1Idx);
                        const player2 = getPlayerName(player2Idx);
                        const matchDate = getMatchDate(matchIndex);
                        
                        return (
                            <div key={matchIndex} className="match">
                                <div className="match-date">{matchDate}</div>
                                <div 
                                    className="player" 
                                    style={getPlayerStyle(player1Idx, 'win2')}
                                >
                                    {player1 || (winners[matchIndex-4] !== null ? "" : "")}
                                </div>
                                <div 
                                    className="player" 
                                    style={getPlayerStyle(player2Idx, 'win2')}
                                >
                                    {player2 || (winners[matchIndex-4+1] !== null ? "" : "")}
                                </div>
                            </div>
                        );
                    })}
                </div>

                {/* Final */}
                <div className="round final">
                    <div className="match">
                        <div className="match-date">{getMatchDate(6)}</div>
                        <div 
                            className="player" 
                            style={getPlayerStyle(winners[4], 'win3')}
                        >
                            {winners[4] !== null ? getPlayerName(winners[4]) : ""}
                        </div>
                        <div 
                            className="player" 
                            style={getPlayerStyle(winners[5], 'win3')}
                        >
                            {winners[5] !== null ? getPlayerName(winners[5]) : ""}
                        </div>
                    </div>
                </div>

                {/* Winner */}
                <div className="round champion">
                    <div 
                        className="champion-box" 
                        style={getPlayerStyle(winners[6], 'win4')}
                    >
                        {winners[6] !== null ? getPlayerName(winners[6]) : "ą¤ąŠą▒ąĄą┤ąĖčéąĄą╗čī"}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default TournamentGrid;