import React, { useEffect } from "react";
import { Routes, Route, useLocation, Navigate, useParams } from "react-router-dom";
import { useDispatch } from "react-redux";

// ąśą╝ą┐ąŠčĆčé ą▓čüąĄčģ čüčéčĆą░ąĮąĖčå
import { IndexPage } from "../pages/IndexPage";
import { TierListPage } from "../pages/TierListPage";
import { EGOsPage } from "../pages/EGOsPage";
import { EGOPage } from "../pages/EGOPage";
import { IdentitiesPage } from "../pages/IdentitiesPage";
import { IdentityPage } from "../pages/IdentityPage";
import { TeamBuilderPage } from "../pages/TeamBuiderPage";
import { StatusesPage } from "../pages/StatusesPage";
import { AboutGamePage } from "../pages/AboutGamePage";
import { ContactPage } from "../pages/ContactPage";
import { AdminPage } from "../pages/AdminPage";
import { TierListPageRedirect } from "../pages/TierListPageRedirect";
import { GraditudePage } from "../pages/GraditudePage";
import { TurnamentPage } from "../pages/TurnamentPage";
import { MirrorDungeonPage } from "../pages/MirrorDungeonPage";
import { MirrorDungeonPageRedirect } from "../pages/MirrorDungeonPageRedirect";
import { EventTestPage } from "../pages/EventTestPage";
import { GuidesPage } from "../pages/GuidesPage";
import { GuidePage } from "../pages/GuidePage";

// ąŁą║čłąĄąĮčŗ
import { filterResetAllAction } from "../store/reducers/filter-reducer";
import { searchChangeValueAction } from "../store/reducers/search-reducer";

const DebugParams = ({ children }: { children: React.ReactNode }) => {
    const params = useParams();
    useEffect(() => {
        console.log('­¤öŹ [AppRouter] Route Params:', params);
    }, [params]);
    return <>{children}</>;
};

export const AppRouter: React.FC = () => {
    const dispatch = useDispatch();
    const location = useLocation();

    useEffect(() => {
        window.scrollTo(0, 0);
        filterResetAllAction(dispatch);
        searchChangeValueAction(dispatch, "");
    }, [location, dispatch]);

    return (
        <Routes>
            <Route path=":lang">
                {/* 1. ąōą╗ą░ą▓ąĮą░čÅ */}
                <Route index element={<IndexPage />} />

                {/* 2. ąøąĖčćąĮąŠčüčéąĖ */}
                <Route path="identities">
                    <Route index element={<IdentitiesPage />} />
                    <Route path=":identityId" element={<DebugParams><IdentityPage /></DebugParams>} />
                </Route>

                {/* 3. EGO */}
                <Route path="ego">
                    <Route index element={<EGOsPage />} />
                    <Route path=":egoId" element={<DebugParams><EGOPage /></DebugParams>} />
                </Route>

                {/* 4. ąóąĖčĆ-ą╗ąĖčüčéčŗ */}
                <Route path="tierlist">
                    <Route index element={<TierListPageRedirect />} />
                    <Route path=":type" element={<DebugParams><TierListPage /></DebugParams>} />
                </Route>

                {/* 5. ąōą░ą╣ą┤čŗ */}
                <Route path="guides">
                    <Route index element={<GuidesPage />} />
                    <Route path=":guideId" element={<DebugParams><GuidePage /></DebugParams>} />
                </Route>

                {/* 6. ąŚąĄčĆą║ą░ą╗čīąĮąŠąĄ ą┐ąŠą┤ąĘąĄą╝ąĄą╗čīąĄ */}
                <Route path="mirror-dungeon">
                    <Route index element={<MirrorDungeonPageRedirect />} />
                    <Route path=":type" element={<DebugParams><MirrorDungeonPage /></DebugParams>} />
                </Route>

                {/* 7. ąóąĄčüčéčŗ ąĖ ąÉą┤ą╝ąĖąĮą║ą░ */}
                <Route path="test">
                    <Route path="description" element={<AdminPage />} />
                    <Route path="event" element={<EventTestPage />} />
                </Route>

                {/* 8. ą×čüčéą░ą╗čīąĮčŗąĄ ąŠą┤ąĖąĮąŠčćąĮčŗąĄ čüčéčĆą░ąĮąĖčåčŗ */}
                <Route path="teambuilder" element={<TeamBuilderPage />} />
                <Route path="statuses" element={<StatusesPage />} />
                <Route path="aboutgame" element={<AboutGamePage />} />
                <Route path="contact" element={<ContactPage />} />
                <Route path="graditude" element={<GraditudePage />} />
                <Route path="turnament" element={<TurnamentPage />} />
            </Route>

            {/* ąĀąĄą┤ąĖčĆąĄą║čé čü čćąĖčüčéąŠą│ąŠ /limbus ąĮą░ /limbus/en */}
            <Route path="/" element={<Navigate to="en/" replace />} />
            
            {/* ą×ą▒čĆą░ą▒ąŠčéą║ą░ ąŠčłąĖą▒ąŠą║ ą▓ąĮčāčéčĆąĖ /limbus/ */}
            <Route path="*" element={<Navigate to="en/" replace />} />
        </Routes>
    );
};