// ą¤čāčéčī ą║ čäą░ą╣ą╗čā: src/tools/getStatusesEntityList.ts

export const getStatusesEntityList = (texts: (string | undefined | null)[]) => {
    const foundStatuses: { [key: string]: number } = {};
    
    // ąØąŠą▓ąŠąĄ čĆąĄą│čāą╗čÅčĆąĮąŠąĄ ą▓čŗčĆą░ąČąĄąĮąĖąĄ: 
    // ąØą░čģąŠą┤ąĖčé čéąĄą║čüčé ą╝ąĄąČą┤čā # #, ą┐čĆąĖ čŹčéąŠą╝ ąŠčéą┤ąĄą╗čÅąĄčé ID ąŠčé čüąŠą┤ąĄčĆąČąĖą╝ąŠą│ąŠ ą▓ čäąĖą│čāčĆąĮčŗčģ čüą║ąŠą▒ą║ą░čģ { }
    const regex = /#([^#\s{}]+)(?:\{[^}]*\})?#/g;

    texts.forEach(text => {
        if (!text || typeof text !== 'string') return;

        let match;
        // ąĪą▒čĆą░čüčŗą▓ą░ąĄą╝ ąĖąĮą┤ąĄą║čü ą┐ąŠąĖčüą║ą░ ą┤ą╗čÅ ą▒ąĄąĘąŠą┐ą░čüąĮąŠčüčéąĖ
        regex.lastIndex = 0; 

        while ((match = regex.exec(text)) !== null) {
            // match[1] ŌĆö čŹčéąŠ čćąĖčüčéčŗą╣ ID čüčéą░čéčāčüą░ (ąĮą░ą┐čĆąĖą╝ąĄčĆ, "burn" ąĖąĘ čéąĄą│ą░ #burn{ąŠą│ąĮąĄą╝}#)
            const statusId = match[1];
            
            if (statusId) {
                // ąŻą▓ąĄą╗ąĖčćąĖą▓ą░ąĄą╝ čüčćąĄčéčćąĖą║ ąĖą╗ąĖ čüčéą░ą▓ąĖą╝ 1
                foundStatuses[statusId] = (foundStatuses[statusId] || 0) + 1;
            }
        }
    });

    return foundStatuses;
};