import { createClient } from '@supabase/supabase-js';

// ąóą▓ąŠąĖ ą║ąŠąĮčüčéą░ąĮčéčŗ
export const SUPABASE_URL = 'https://supabasedomen.gll-fun.com'; 
export const SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJyb2xlIjoiYW5vbiIsImlzcyI6InN1cGFiYXNlIn0.t-9_E-M0Q8_D-L_M-G_E-M0Q8_D-L_M-G_E-M0Q8_D-L_M';

// ąÜą░čüčéąŠą╝ąĮąŠąĄ čģčĆą░ąĮąĖą╗ąĖčēąĄ ąĮą░ ą▒ą░ąĘąĄ ą║čāą║ąĖ
const cookieStorage = {
  getItem: (key: string) => {
    if (typeof document === 'undefined') return null;
    const cookies = document.cookie.split('; ');
    const cookie = cookies.find(row => row.startsWith(`${key}=`));
    return cookie ? decodeURIComponent(cookie.split('=')[1]) : null;
  },
  setItem: (key: string, value: string) => {
    if (typeof document === 'undefined') return;
    // ąŻčüčéą░ąĮą░ą▓ą╗ąĖą▓ą░ąĄą╝ ą║čāą║čā ąĮą░ 365 ą┤ąĮąĄą╣ (ą╝ąŠąČąĮąŠ ąĮą░čüčéčĆąŠąĖčéčī ą┐ąŠą┤ čüąĄą▒čÅ)
    document.cookie = `${key}=${encodeURIComponent(value)}; path=/; max-age=${60 * 60 * 24 * 365}; SameSite=Lax; Secure`;
  },
  removeItem: (key: string) => {
    if (typeof document === 'undefined') return;
    document.cookie = `${key}=; path=/; expires=Thu, 01 Jan 1970 00:00:00 GMT`;
  },
};

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY, {
  auth: {
    storage: cookieStorage, // ą¤ąŠą┤ą║ą╗čÄčćą░ąĄą╝ ąĮą░čłąĄ "ą▓ąŠą╗čłąĄą▒ąĮąŠąĄ" čģčĆą░ąĮąĖą╗ąĖčēąĄ
    persistSession: true,
    autoRefreshToken: true,
    detectSessionInUrl: true
  }
});