import React, { useState, useEffect } from 'react';
import { IdentityInterface } from '../../../../store/reducers/ids-reducer';
import { IPassive } from '../EntityFullInfoSkills';
import "./EntityFullInfoPassive.css";
import { SkillCoinDescription } from "../../../guides/text-formatter/SkillCoinDescription";
import { useTranslation } from 'react-i18next';
import { useTypedSelector } from '../../../../hooks/useTypedSelector';

interface IEntityFullInfoProps {
    identity: IdentityInterface;
    passive: IPassive;
}

export const EntityFullInfoPassive: React.FC<IEntityFullInfoProps> = ({ identity, passive }) => {
    const { imgUrl } = identity;
    const { t, i18n } = useTranslation();
    const { selectedUptie } = useTypedSelector(s => s.uptieReducer);
    
    const [currentLanguage, setCurrentLanguage] = useState(i18n.language);
    const [tooltipVisible, setTooltipVisible] = useState(false);
    
    useEffect(() => {
        setCurrentLanguage(i18n.language);
    }, [i18n.language]);

    const passiveKeyBase = passive.type === t("ItemIdentityInfo.battlePassive") 
        ? "descriptionPassive1" 
        : "descriptionPassive2";
    
    const uptieSuffix = selectedUptie === 4 ? '' : selectedUptie > 0 ? selectedUptie.toString() : '';
    const descriptionKey = `${passiveKeyBase}${currentLanguage.toUpperCase()}${uptieSuffix}` as keyof typeof identity;

    const getDescriptionWithFallback = () => {
        if (identity[descriptionKey] !== undefined && 
            identity[descriptionKey] !== null && 
            identity[descriptionKey] !== "1") {
            return identity[descriptionKey] as string;
        }
        
        let fallbackUptie = selectedUptie - 1;
        while (fallbackUptie >= 1) {
            const fallbackSuffix = fallbackUptie === 4 ? '' : fallbackUptie > 0 ? fallbackUptie.toString() : '';
            const fallbackKey = `${passiveKeyBase}${currentLanguage.toUpperCase()}${fallbackSuffix}` as keyof typeof identity;
            
            if (identity[fallbackKey] !== undefined && 
                identity[fallbackKey] !== null && 
                identity[fallbackKey] !== "1") {
                return identity[fallbackKey] as string;
            }
            
            fallbackUptie--;
        }
        
        return passive.description;
    };

    const description = getDescriptionWithFallback();

    const isBattlePassiveWithSplit = passive.type === t("ItemIdentityInfo.battlePassive") && 
                                   description && 
                                   description.includes("|");

    const [currentTooltipName, setCurrentTooltipName] = useState("");

    const handleMouseEnter = (name: string) => {
        if (name.length > 30) {
            setTooltipVisible(true);
            setCurrentTooltipName(name);
        }
    };

    const handleMouseLeave = () => {
        setTooltipVisible(false);
        setCurrentTooltipName("");
    };

    const passiveNames = passive.name.split(";");

    const shouldShowLock = (index: number) => {
    const isBattlePassive = passive.type === t("ItemIdentityInfo.battlePassive");
    
    // ąĪą┐ąĄčåąĖą░ą╗čīąĮą░čÅ ą╗ąŠą│ąĖą║ą░ ą┤ą╗čÅ id_152
    const isSpecialCase = identity.imgUrl === "id_152";
    
    if (isSpecialCase) {
        if (selectedUptie === 1) {
            // ąöą╗čÅ ą░ą┐čéą░čÅ 1: ą▒ą╗ąŠą║ąĖčĆčāąĄą╝ ąÆąĪąĢ čćą░čüčéąĖ BattlePassive
            return true;
        } else if (selectedUptie === 2) {
            // ąöą╗čÅ ą░ą┐čéą░čÅ 2: ą▒ą╗ąŠą║ąĖčĆčāąĄą╝ ą┐ąĄčĆą▓čāčÄ čćą░čüčéčī BattlePassiveWithSplit
            if (isBattlePassive && isBattlePassiveWithSplit) {
                return index === 0;
            }
            return !isBattlePassive; // ą┐ąŠą┤ą┤ąĄčĆąČą║čā ą▒ą╗ąŠą║ąĖčĆčāąĄą╝ ą▓čüąĄą│ą┤ą░
        }
    } else {
        // ąĪčéą░ąĮą┤ą░čĆčéąĮą░čÅ ą╗ąŠą│ąĖą║ą░ ą┤ą╗čÅ ą┤čĆčāą│ąĖčģ ID
        if (isBattlePassive && !isBattlePassiveWithSplit) {
            // ąöąøą» ąæą×ąĢąÆą×ąÖ ą¤ąÉąĪąĪąśąÆąÜąś ąæąĢąŚ ąĀąÉąŚąöąĢąøąĢąØąśą» ąĖčüą┐ąŠą╗čīąĘčāąĄą╝ passiveTier
            const passiveTier = identity.passiveTier;
            
            if (passiveTier !== undefined && passiveTier !== null && passiveTier !== "") {
                // ąÜąŠąĮą▓ąĄčĆčéąĖčĆčāąĄą╝ passiveTier ą▓ čćąĖčüą╗ąŠ ą┤ą╗čÅ čüčĆą░ą▓ąĮąĄąĮąĖčÅ
                const tier = parseInt(passiveTier, 10);
                
                // ąĢčüą╗ąĖ passiveTier = 1 - ą┐ą░čüčüąĖą▓ ą▓čüąĄą│ą┤ą░ ąŠčéą║čĆčŗčé
                // ąĢčüą╗ąĖ passiveTier = 2 - ąŠčéą║čĆčŗą▓ą░ąĄčéčüčÅ ą┐čĆąĖ selectedUptie 2 ąĖ ą▓čŗčłąĄ
                // ąĢčüą╗ąĖ passiveTier = 3 - ąŠčéą║čĆčŗą▓ą░ąĄčéčüčÅ ą┐čĆąĖ selectedUptie 3 ąĖ ą▓čŗčłąĄ
                // ąĢčüą╗ąĖ passiveTier = 4 - ąŠčéą║čĆčŗą▓ą░ąĄčéčüčÅ ą┐čĆąĖ selectedUptie 4
                
                if (tier === 1) {
                    return false; // ąÆčüąĄą│ą┤ą░ ąŠčéą║čĆčŗčé
                } else if (tier === 2) {
                    return selectedUptie < 2;
                } else if (tier === 3) {
                    return selectedUptie < 3;
                } else if (tier === 4) {
                    return selectedUptie < 4;
                }
            }
        }
        
        // ążąŠą╗ą▒čŹą║ ą╗ąŠą│ąĖą║ą░ ą┤ą╗čÅ čĆą░ąĘą┤ąĄą╗ąĄąĮąĮčŗčģ ą▒ąŠąĄą▓čŗčģ ą┐ą░čüčüąĖą▓ąŠą║ ąĖ ą┐ąŠą┤ą┤ąĄčĆąČą║ąĖ ą┐ą░čüčüąĖą▓ą║ąĖ
        if (selectedUptie === 1) {
            // For uptie 1:
            // - For battle passive: lock only last part
            // - For support passive: lock everything
            return (isBattlePassive && isBattlePassiveWithSplit && index === passiveNames.length - 1) || !isBattlePassive;
        } else if (selectedUptie === 2) {
            // For uptie 2: lock only support passive (descriptionPassive2)
            return !isBattlePassive;
        }
    }
    
    // For uptie 3 and 4: no locks
    return false;
};
    return (
        <div className="entityFullInfo-skill-r">
            {isBattlePassiveWithSplit ? (
                <div style={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: "20px", marginBottom: "15px" }}>
                    {passiveNames.map((nameBP, index) => {
                        const splitDescriptions = description.split("|").map(part => part.trim());
                        const descriptionPart = splitDescriptions[index] || '';
                        const showLock = shouldShowLock(index);
                        
                        return (
                            <article className={`entityFullInfo-passive`} key={index} style={{ position: 'relative' }}>
                                {showLock && (
                                    <div className="lock-overlay">
                                        <div className="lock-center">
                                            <img src="/images/general/lock.png" alt="Lock Center" />
                                        </div>
                                    </div>
                                )}
                                <span className={`entityFullInfo-passive-index`}>{passive.type}</span>
                                <p
                                    className={`passive-name`}
                                    onMouseEnter={() => handleMouseEnter(nameBP)}
                                    onMouseLeave={handleMouseLeave}
                                >
                                    {nameBP}
                                </p>
                                {tooltipVisible && currentTooltipName === nameBP && (
                                    <div className="tooltip">
                                        {nameBP}
                                    </div>
                                )}
                                {index === passiveNames.length - 1 && renderSinIcons(passive, imgUrl, t)}
                                <SkillCoinDescription description={descriptionPart} />
                            </article>
                        );
                    })}
                </div>
            ) : (
                <article className={`entityFullInfo-passive`} style={{ position: 'relative' }}>
                    {shouldShowLock(0) && (
                        <div className="lock-overlay">
                            <div className="lock-center">
                                <img src="/images/general/lock.png" alt="Lock Center" />
                            </div>
                        </div>
                    )}
                    <span className={`entityFullInfo-passive-index`}>{passive.type}</span>
                    <p
                        className={`passive-name ${passive.sin}-sin-color`}
                        onMouseEnter={() => handleMouseEnter(passive.name)}
                        onMouseLeave={handleMouseLeave}
                    >
                        {passive.name}
                    </p>
                    {tooltipVisible && currentTooltipName === passive.name && (
                        <div className="tooltip">
                            {passive.name}
                        </div>
                    )}
                    {renderSinIcons(passive, imgUrl, t)}
                    <SkillCoinDescription description={description} />
                </article>
            )}
        </div>
    );
};

function renderSinIcons(passive: IPassive, imgUrl: string, t: any) {
    // ą¤čĆąĖą▓ąŠą┤ąĖą╝ ą║ ą╝ą░čüčüąĖą▓čā, ą┤ą░ąČąĄ ąĄčüą╗ąĖ ą┐čĆąĖčłą╗ą░ ąŠą┤ąĖąĮąŠčćąĮą░čÅ čüčéčĆąŠą║ą░/čćąĖčüą╗ąŠ
    const sins = Array.isArray(passive.sin) ? passive.sin : [passive.sin];
    const counts = Array.isArray(passive.count) ? passive.count : [passive.count];

    return (
        <div className="passive-atk tooltip-container">
            {sins.map((sinName, index) => (
                <React.Fragment key={index}>
                    <img 
                        src={`${process.env.PUBLIC_URL}/images/sins/${sinName}.webp`} 
                        alt={imgUrl} 
                    />
                    {/* ą¤čĆąŠą▒ąĄą╗ ą┐ąŠčüą╗ąĄ X, ąĖ ą┐čĆąŠą▒ąĄą╗ ą┐ąŠčüą╗ąĄ čüą░ą╝ąŠą│ąŠ čćąĖčüą╗ą░ ą┤ą╗čÅ ąŠčéčüčéčāą┐ą░ ąŠčé čüą╗ąĄą┤čāčÄčēąĄą╣ ąĖą║ąŠąĮą║ąĖ ąĖą╗ąĖ čéąĄą║čüčéą░ */}
                    <span>x{counts[index]}&nbsp;</span>
                </React.Fragment>
            ))}
            
            {/* ąóąĄą║čüčé čāčüą╗ąŠą▓ąĖčÅ čéąĄą┐ąĄčĆčī ą▒čāą┤ąĄčé ąĖą╝ąĄčéčī ąŠčéčüčéčāą┐ ąŠčé ą┐ąŠčüą╗ąĄą┤ąĮąĄą╣ čåąĖčäčĆčŗ ą▒ą╗ą░ą│ąŠą┤ą░čĆčÅ &nbsp; ą▓čŗčłąĄ */}
            <span>
                {passive.condition === "res" 
                    ? t("EntityFullInfoPassive.res") 
                    : t("EntityFullInfoPassive.owned")}
            </span>
        </div>
    );
}