import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useQueryClient } from 'react-query';
import { useDispatch } from 'react-redux';
import { Link } from 'react-router-dom';
import { mdSelectGiftIdAction } from '../../../../store/reducers/md-reducer';
import { MDGift } from '../../../../store/reducers/md-gift-interface';
import './MDCrafts.css';

type Craft = {
    requirements: string[],
    result: string,
    status?: string
}

const romanNumerals: Record<string, string> = {
    6: 'EX',
    5: 'V',
    4: 'IV',
    3: 'III',
    2: 'II',
    1: 'I'
};

const statusOrder = ['burn', 'bleed', 'tremor', 'rupture', 'sinking', 'poise', 'charge', 'blunt', 'slash', 'pierce'];

const GiftItem: React.FC<{ gift: MDGift }> = ({ gift }) => {
    const dispatch = useDispatch();
    const { i18n, t } = useTranslation();
    const { nameRU, nameEN, sin } = gift;
    return <div className='GiftItem-item'>
        <picture>
            <Link to={`/limbus/${i18n.language}/mirror-dungeon/gifts`}
                onClick={() => {
                    mdSelectGiftIdAction(
                        dispatch,
                        gift.id
                    )
                }}
                className='GiftItem-img-wrapper'>
                <img
                    className='MDcrafts-gift-img'
                    src={`${process.env.PUBLIC_URL}/images/md-gifts/${gift.id}.webp`}
                    alt={i18n.language === "ru" ? nameRU : nameEN} />
                <div className={`GiftItem-bar GiftItem-bar--${(gift.id !== "gift_0") ? sin : "none"}`} />
                {
                    !!gift && <span className='gift-tier' style={{color: gift.tier === 6 ? '#9ae23e' : '#fbc601'}}> 
                        {romanNumerals[gift.tier]} 
                    </span>
                    }
                {
                    !!gift && gift.keyword !== "none" &&
                    <img
                        className='gift-keyword-img'
                        src={
                            ["blunt", "pierce", "slash"].includes(gift.keyword)
                                ? `${process.env.PUBLIC_URL}/images/dmg-type/${gift.keyword}.webp`
                                : `${process.env.PUBLIC_URL}/images/tags/${gift.keyword}.webp`
                        }
                        alt={gift?.keyword} />
                }
                <div className={`GiftItem-shadow`} />
                <div className={`GiftItem-info GiftItem-info--${i18n.language}`} >{t(`GiftItem.info`)}</div>
            </Link>
            <caption>
                {(() => {
                    const name = i18n.language === "ru" ? nameRU : nameEN;
                    return name.length > 9 ? `${name.slice(0, 9)}...` : name;
                })()}
            </caption>
        </picture>
    </div>
}

export const MDCrafts: React.FC = () => {
    const gifts = useQueryClient().getQueryData("md-gifts") as MDGift[] | null;
    const { i18n, t } = useTranslation();
    const [statusFilter, setStatusFilter] = useState<string | null>(null);
    const [isFiltersCollapsed, setIsFiltersCollapsed] = useState(false);

    if (!gifts) return null;

    const crafts: Craft[] = gifts.reduce((acc: Craft[], curr) => {
        const { obtainEN, id, keyword } = curr;
        if (id === "gift_0") return acc;
        if (!obtainEN.includes("#")) return acc;
        const splitted = obtainEN.split("#");
        if (splitted.length % 2 != 1) return acc;
        const requirements = [];
        for (let i = 1; i < splitted.length; i += 2) {
            requirements.push(splitted[i])
        }
        acc.push({
            requirements,
            result: id,
            status: keyword
        })
        return acc;
    }, []);

    const filteredCrafts = statusFilter 
        ? crafts.filter(craft => craft.status === statusFilter)
        : crafts;

    const sortedCrafts = [...filteredCrafts].sort((a, b) => {
        const aIndex = statusOrder.indexOf(a.status || '');
        const bIndex = statusOrder.indexOf(b.status || '');
        
        if (aIndex !== -1 && bIndex !== -1) {
            return aIndex - bIndex;
        }
        if (aIndex !== -1) return -1;
        if (bIndex !== -1) return 1;
        return 0;
    });

    const toggleFilters = () => {
        setIsFiltersCollapsed(!isFiltersCollapsed);
    };

    return (
        <div className='MDcrafts-wrapper'>
            <div className={`filters2 ${isFiltersCollapsed ? 'filters-main-header--collapse' : ''}`}>
                <div className="filters-main2">
                    <div className="filters-section">
                        <div className={`section-expanded ${isFiltersCollapsed ? 'filters-section--hidden' : ''}`}>
                        {statusOrder.map(status => (
                            <div 
                                key={status}
                                className={`filters-filter ${statusFilter === status ? 'filters-filter--active' : ''}`}
                                onClick={() => setStatusFilter(statusFilter === status ? null : status)}
                                style={{position: 'relative'}}  // ąöąŠą▒ą░ą▓ą╗čÅąĄą╝ relative ą┤ą╗čÅ ą┐ąŠąĘąĖčåąĖąŠąĮąĖčĆąŠą▓ą░ąĮąĖčÅ ą╗ąĖąĮąĖąĖ
                            >
                                <img 
                                    className="filters-filter-img"
                                    src={`${process.env.PUBLIC_URL}/images/${
                                        ["blunt", "pierce", "slash"].includes(status) 
                                            ? `dmg-type/${status}.webp` 
                                            : `tags/${status}.webp`
                                    }`} 
                                    alt={status}
                                />
                                <span className="filters-filter-tooltip">{t(`status.${status}`)}</span>
                                {statusFilter === status && (
                                    <div className="filters-frame-line"></div>
                                )}
                            </div>
                        ))}
                        {/* ąÜąĮąŠą┐ą║ą░ "ą¤ąŠą║ą░ąĘą░čéčī ą▓čüąĄ" */}
                        <div 
                            className={`filters-filter ${!statusFilter ? 'filters-filter--active' : ''}`}
                            onClick={() => setStatusFilter(null)}
                            title={t('Show all')}
                            style={{position: 'relative'}}
                        >
                            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                                <path d="M18 6L6 18M6 6L18 18" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
                            </svg>
                            {!statusFilter && (
                                <div className="filters-frame-line"></div>
                            )}
                        </div>
                        </div>
                    </div>
                </div>
            </div>
            <div className="filters-main-header2">
                <h2>{t(`GiftItem.crafts`)} ({filteredCrafts.length})</h2>
                <div className="filters-header-btns">
                    <button 
                        className={`btn-filters show-filters`}
                        onClick={toggleFilters}
                    >
                        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                            <path d="M4 6H20M4 12H20M4 18H20" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
                        </svg>
                        {isFiltersCollapsed ? t('Show filters') : t('Hide filters')}
                    </button>
                    
                </div>
            </div>
            
            
            
            <div className="MDcrafts-list">
                {sortedCrafts.map((c, index) => {
                    const { requirements, result } = c;
                    const gift = gifts.find(g => g.id === result);
                    if (!gift) return null;

                    return <div className='MDcrafts-line' key={index}>
                        <div className='MDcrafts-req'>
                            {requirements.map((r, index) => {
                                const gift = gifts.find(g => g.id === r);
                                if (!gift) {
                                    return null;
                                }
                                return <React.Fragment key={index}>
                                    <GiftItem gift={gift} />
                                    {(index !== requirements.length - 1)
                                        ? <div className='MDcrafts-sign'>+</div>
                                        : null}
                                </React.Fragment>
                            })}
                        </div>
                        <div className='MDcrafts-sign'>=</div>
                        <div className='MDcrafts-result'>
                            <GiftItem gift={gift} />
                        </div>
                    </div>
                })}
            </div>
        </div>
    );
};