import React, { useEffect, useRef } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { useDispatch } from "react-redux";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { EGOInterface } from "../../store/reducers/ego-reducer";
import { searchChangeTargetRefAction } from "../../store/reducers/search-reducer";
import { isFilterMatching } from "../../tools/isFilterMatching";
import { ItemEntity } from "../item-entity/ItemEntity";
import { ListSinnerBar } from "../list-sinner-bar/ListSinnerBar";
import { StatusesInterface } from "../../store/reducers/statuses-reducer";
import "./ListEgo.css";

export const ListEgo: React.FC = () => {
    const ego = useQueryClient().getQueryData("ego") as EGOInterface[] | null;
    const statuses = useQueryClient().getQueryData('statuses') as StatusesInterface[];
    const filterState = useTypedSelector(state => state.filterReducer);
    const searchState = useTypedSelector(state => state.searchReducer);
    const containerRef = useRef(null);
    const dispatch = useDispatch();
    const { t, i18n } = useTranslation();

    useEffect(() => {
        searchChangeTargetRefAction(dispatch, containerRef)
    }, [dispatch])

    const egoMap: { [key: string]: React.ReactNode[] } = {
        "new": [], "yi sang": [], "faust": [], "don quixote": [], "ryoshu": [],
        "mersault": [], "hong lu": [], "heathcliff": [], "ishmael": [], "rodion": [],
        "sinclair": [], "outis": [], "gregor": [],
    };

    let totalCount = 0;

    if (ego) {
        const egoRarityOrder: Record<string, number> = { "ALEPH": 5, "WAW": 4, "HE": 3, "TETH": 2, "ZAYIN": 1 };
        const sortedEgo = [...ego].sort((a, b) => {
            const weightA = egoRarityOrder[a.rarity] || 0;
            const weightB = egoRarityOrder[b.rarity] || 0;
            if (weightB !== weightA) return weightB - weightA;
            return new Date(b.releaseDate).getTime() - new Date(a.releaseDate).getTime();
        });

        for (let i = 0; i < sortedEgo.length; i++) {
            const currentEGO = sortedEgo[i];
            const { isNew, imgUrl, sinner, egoTier } = currentEGO;

            if (!egoTier || egoTier.trim() === "") continue;
            if (!isFilterMatching(filterState, searchState, currentEGO, i18n.language, statuses)) continue;

            if (!!(+isNew)) {
                egoMap.new.push(
                    <ItemEntity 
                        hideFooter={true} // ąöąŠą▒ą░ą▓ą╗ąĄąĮąŠ
                        animationDelay={500} 
                        entity={currentEGO} 
                        key={`${imgUrl}-new`} 
                    />
                );
            }

            if (sinner in egoMap) {
                egoMap[sinner].push(
                    <ItemEntity 
                        hideFooter={true} // ąöąŠą▒ą░ą▓ą╗ąĄąĮąŠ
                        animationDelay={500} 
                        entity={currentEGO} 
                        key={imgUrl} 
                    />
                );
            }
            totalCount++;
        }
    }

    return (
        <section ref={containerRef} className={"list-ego"}>
            <span className={"list-ego-span"}>{`${t("ListEgo.header")} (${totalCount})`}</span>
            {totalCount !== 0 ? (
                Object.entries(egoMap).map(([key, value]) => {
                    if (!value.length) return null;
                    return <ListSinnerBar key={key} sinner={key} data={value} />
                })
            ) : <p>{t("ListEgo.empty")}</p>}
        </section>
    )
}