import React, { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { Link } from "react-router-dom";
import "./ItemGuide.css";
import { GuideInterface } from "../../store/reducers/guides-reducer";
import { addTag, GuideTagInterface, removeTag, TagsState } from "../../store/reducers/guides-tags-reducer";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { useDispatch } from "react-redux";
import { filterChangeTypeAction } from "../../store/reducers/filter-reducer";

const formatDateFromISO = (dateString: string | number): string => {
    console.log('ą¤ąŠą╗čāčćąĄąĮąĮą░čÅ ą┤ą░čéą░:', dateString);
    
    let newDate: Date;

    if (typeof dateString === 'string') {
        newDate = new Date(dateString);
    } else if (typeof dateString === 'number') {
        // ąĢčüą╗ąĖ čŹčéąŠ ą║ąŠą╗ąĖčćąĄčüčéą▓ąŠ ą┤ąĮąĄą╣ čü ąĮą░čćą░ą╗ą░ čŹą┐ąŠčģąĖ Excel (30 ą┤ąĄą║ą░ą▒čĆčÅ 1899 ą│ąŠą┤ą░)
        const excelStartDate = new Date(1899, 11, 30);
        const millisecondsPerDay = 24 * 60 * 60 * 1000;
        newDate = new Date(excelStartDate.getTime() + dateString * millisecondsPerDay);
    } else {
        console.error('Invalid date format');
        throw new Error('Invalid date format');
    }

    // ą¤čĆąŠą▓ąĄčĆčÅąĄą╝, čÅą▓ą╗čÅąĄčéčüčÅ ą╗ąĖ ą┤ą░čéą░ ą┤ąŠą┐čāčüčéąĖą╝ąŠą╣
    if (isNaN(newDate.getTime())) {
        console.error('Invalid date format');
        throw new Error('Invalid date format');
    }

    const month = String(newDate.getMonth() + 1).padStart(2, '0');
    const day = String(newDate.getDate()).padStart(2, '0');
    const formattedDate = `${day}.${month}.${newDate.getFullYear()}`;
    console.log('ą×čéčäąŠčĆą╝ą░čéąĖčĆąŠą▓ą░ąĮąĮą░čÅ ą┤ą░čéą░:', formattedDate);
    return formattedDate;
};


export interface IItemEntity{
    entity: GuideInterface;
    tags: GuideTagInterface[],
    animationDelay?:number;
}
export const ItemGuide: React.FC<IItemEntity> = ({ entity, tags }) => {
    let { ids, date, nameRu, nameEn, secretOrNot } = entity;
    const { i18n } = useTranslation();
    
    // ąĪąŠčüčéąŠčÅąĮąĖąĄ ą┤ą╗čÅ ąŠčéčüą╗ąĄąČąĖą▓ą░ąĮąĖčÅ ąĮą░ąČą░čéąŠą╣ ą║ąŠą╝ą▒ąĖąĮą░čåąĖąĖ ą║ą╗ą░ą▓ąĖčł
    const [isSecretVisible, setIsSecretVisible] = useState(false);
    
    // ą¤čĆąŠą▓ąĄčĆčÅąĄą╝, čÅą▓ą╗čÅąĄčéčüčÅ ą╗ąĖ ą│ą░ą╣ą┤ čüąĄą║čĆąĄčéąĮčŗą╝
    const isSecretGuide = secretOrNot === "Yes";

    // ąŁčäčäąĄą║čé ą┤ą╗čÅ ą┤ąŠą▒ą░ą▓ą╗ąĄąĮąĖčÅ ąĖ čāą┤ą░ą╗ąĄąĮąĖčÅ ąŠą▒čĆą░ą▒ąŠčéčćąĖą║ą░ ą║ą╗ą░ą▓ąĖą░čéčāčĆčŗ
    useEffect(() => {
        const handleKeyDown = (event: KeyboardEvent) => {
            // ą¤čĆąŠą▓ąĄčĆčÅąĄą╝ ą║ąŠą╝ą▒ąĖąĮą░čåąĖčÄ Alt + Ctrl
            if (event.altKey && event.ctrlKey) {
                setIsSecretVisible(true);
            }
        };

        const handleKeyUp = (event: KeyboardEvent) => {
            // ąÜąŠą│ą┤ą░ ą║ą╗ą░ą▓ąĖčłąĖ ąŠčéą┐čāčēąĄąĮčŗ, čüą║čĆčŗą▓ą░ąĄą╝ čüąĄą║čĆąĄčéąĮčŗąĄ ą│ą░ą╣ą┤čŗ
            if (!event.altKey && !event.ctrlKey) {
                setIsSecretVisible(false);
            }
        };

        // ąöąŠą▒ą░ą▓ą╗čÅąĄą╝ ąŠą▒čĆą░ą▒ąŠčéčćąĖą║ąĖ čüąŠą▒čŗčéąĖą╣
        document.addEventListener('keydown', handleKeyDown);
        document.addEventListener('keyup', handleKeyUp);

        // ą×čćąĖčüčéą║ą░ ąŠą▒čĆą░ą▒ąŠčéčćąĖą║ąŠą▓ ą┐čĆąĖ čĆą░ąĘą╝ąŠąĮčéąĖčĆąŠą▓ą░ąĮąĖąĖ ą║ąŠą╝ą┐ąŠąĮąĄąĮčéą░
        return () => {
            document.removeEventListener('keydown', handleKeyDown);
            document.removeEventListener('keyup', handleKeyUp);
        };
    }, []);

    function handleFilterChange(key: string) {
        filterChangeTypeAction(dispatch, key);
       
        if (tagsReducer.selectedTags.includes(key)) {
            dispatch(removeTag(key));
        } else {
            dispatch(addTag(key));
        }
    }

    const tagsReducer = useTypedSelector(state => state.tagsReducer) as TagsState;
    const selectedTags = tagsReducer.selectedTags;
    const dispatch = useDispatch();

    // ąĢčüą╗ąĖ ą│ą░ą╣ą┤ čüąĄą║čĆąĄčéąĮčŗą╣ ąĖ ą║ąŠą╝ą▒ąĖąĮą░čåąĖčÅ ą║ą╗ą░ą▓ąĖčł ąĮąĄ ąĮą░ąČą░čéą░ - ąĮąĄ ąŠčéąŠą▒čĆą░ąČą░ąĄą╝ ąĄą│ąŠ
    if (isSecretGuide && !isSecretVisible) {
        return null; // ąÆąŠąĘą▓čĆą░čēą░ąĄą╝ null, čćčéąŠą▒čŗ čüą║čĆčŗčéčī ą║ąŠą╝ą┐ąŠąĮąĄąĮčé
    }

    return (
        <li className={`guide-info-item ${isSecretGuide ? 'secret-guide' : ''}`} key={ids}>
            {/* ąöąŠą▒ą░ą▓ą╗čÅąĄą╝ ą║ą╗ą░čüčü ą┤ą╗čÅ čüčéąĖą╗ąĖąĘą░čåąĖąĖ čüąĄą║čĆąĄčéąĮčŗčģ ą│ą░ą╣ą┤ąŠą▓ */}
            {isSecretGuide && (
                <div className="secret-badge">
                    {i18n.language === 'ru' ? 'ąĪąĄą║čĆąĄčéąĮčŗą╣ ą│ą░ą╣ą┤' : 'Secret Guide'}
                </div>
            )}
            <Link to={`/limbus/${i18n.language}/guides/${ids}`} className="guide-info-link-wrapper">
                <div className="guide-info-content">
                    <time className="guide-info-date">
                        {(i18n.language == 'ru') ? 'ą¤ąŠčüą╗ąĄą┤ąĮąĄąĄ ąĖąĘą╝ąĄąĮąĄąĮąĖąĄ' : 'Last updated on'}: {formatDateFromISO(date)}
                    </time>
                    <h2 className="guide-info-title">
                        {(i18n.language === "ru") ? nameRu : nameEn}
                    </h2>
                    <div className="guide-info-image-wrapper">
                        <img 
                            src={`${process.env.PUBLIC_URL}/images/guides/${ids}/${ids}.webp`} 
                            alt={(i18n.language === "ru") ? nameRu : nameEn}
                            className="guide-info-image" 
                        />
                    </div>
                </div>
            </Link>
            <div className="guide-tags-container">
                <div className="guide-tags">
                    {tags?.slice(0, 3).map((tag: GuideTagInterface) => (
                        <button
                            key={tag.Id}
                            className={`tag-item ${selectedTags.includes(tag.Id) ? 'active' : ''}`}
                            onClick={() => handleFilterChange(tag.Id)}
                        >
                            {(i18n.language == 'ru') ? tag.nameRu : tag.nameEn}
                        </button>
                    ))}
                </div>
            </div>
        </li>
    );
};