import { useQuery, QueryClient } from "react-query";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../tools/supabaseClient";
import { eventsListKeys } from "../constants/eventsListKeys";

const CACHE_KEY = 'events_list_cache';
const CACHE_TIME = 15 * 60 * 1000; // 15 ą╝ąĖąĮčāčé

const getDataFromCache = () => {
  if (typeof window === 'undefined') return null;
  const cachedData = localStorage.getItem(CACHE_KEY);
  if (cachedData) {
    const { data, timestamp } = JSON.parse(cachedData);
    if (Date.now() - timestamp < CACHE_TIME) return data;
  }
  return null;
};

const setDataToCache = (data: any) => {
  localStorage.setItem(CACHE_KEY, JSON.stringify({ data, timestamp: Date.now() }));
};

const useFetchEventsListAction = async () => {
  const cached = getDataFromCache();
  if (cached) return cached;

  // ąÆąØąśą£ąÉąØąśąĢ: ą¤čĆąŠą▓ąĄčĆčī ąĮą░ąĘą▓ą░ąĮąĖąĄ čéą░ą▒ą╗ąĖčåčŗ ą▓ Supabase. 
  // ąĢčüą╗ąĖ ą▓ ąæąö ąŠąĮą░ ąĮą░ąĘčŗą▓ą░ąĄčéčüčÅ 'events', ąĘą░ą╝ąĄąĮąĖ /rest/v1/events_list ąĮą░ /rest/v1/events
  const url = `${SUPABASE_URL}/rest/v1/events?select=*&apikey=${SUPABASE_ANON_KEY}`;

  const response = await fetch(url);
  if (!response.ok) throw new Error("ą×čłąĖą▒ą║ą░ ąĘą░ą│čĆčāąĘą║ąĖ čüą┐ąĖčüą║ą░ čüąŠą▒čŗčéąĖą╣");

  const rawData = await response.json();

  // ą¤čĆąŠą│ąŠąĮčÅąĄą╝ čćąĄčĆąĄąĘ čéą▓ąŠąĖ ą▓ą░ą╗ąĖą┤ą░čéąŠčĆčŗ
  const validatedData = rawData.map((row: any) => {
    const item: any = {};
    
    eventsListKeys.forEach(({ key, validation }) => {
      // ąśčēąĄą╝ ąĘąĮą░čćąĄąĮąĖąĄ (čü ą┐ąŠą┤ą┤ąĄčĆąČą║ąŠą╣ čĆą░ąĘąĮąŠą│ąŠ čĆąĄą│ąĖčüčéčĆą░)
      const rawValue = row[key] !== undefined ? row[key] : row[key.toLowerCase()];
      
      // ąÆčŗąĘčŗą▓ą░ąĄą╝ čéą▓ąŠą╣ ą▓ą░ą╗ąĖą┤ą░čéąŠčĆ (validationToString ąĖ čé.ą┤.)
      const { validatedVal } = validation(rawValue ?? "");
      
      item[key] = validatedVal;
    });

    return item;
  });

  setDataToCache(validatedData);
  return validatedData;
};

export const useFetchEventsList = () => {
  return useQuery("events", useFetchEventsListAction, {
    staleTime: CACHE_TIME,
    cacheTime: Infinity,
    refetchOnWindowFocus: false,
    retry: 5,
    onError: (error) => {
      console.error("Error fetching events list:", error);
    },
  });
};

export const createQueryClient = () => {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { staleTime: CACHE_TIME, cacheTime: Infinity } },
  });

  if (typeof window !== 'undefined') {
    const cachedData = getDataFromCache();
    if (cachedData) {
      queryClient.setQueryData("events", cachedData);
    }
  }
  return queryClient;
};