import { useQuery, QueryClient } from "react-query";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../tools/supabaseClient";
import { idsKeys } from "../constants/idsKeys"; // ąóą▓ąŠą╣ ą║ąŠąĮčäąĖą│ ą║ą╗čÄčćąĄą╣

const CACHE_KEY = 'identities_cache';
const CACHE_TIME = 15 * 60 * 1000; // 35 ą╝ąĖąĮčāčé

const getDataFromCache = () => {
  if (typeof window === 'undefined') return null;
  const cachedData = localStorage.getItem(CACHE_KEY);
  if (cachedData) {
    const { data, timestamp } = JSON.parse(cachedData);
    if (Date.now() - timestamp < CACHE_TIME) return data;
  }
  return null;
};

const setDataToCache = (data: any) => {
  localStorage.setItem(CACHE_KEY, JSON.stringify({ data, timestamp: Date.now() }));
};

const useFetchIdsAction = async () => {
  const cached = getDataFromCache();
  if (cached) return cached;

  const url = `${SUPABASE_URL}/rest/v1/ids?select=*&apikey=${SUPABASE_ANON_KEY}`;
  const response = await fetch(url);
  if (!response.ok) throw new Error("Supabase fetch error");

  const rawData = await response.json();

  // ą¤čĆąĖą╝ąĄąĮčÅąĄą╝ čéą▓ąŠčÄ ą╗ąŠą│ąĖą║čā ą▓ą░ą╗ąĖą┤ą░čåąĖąĖ ą║ ą║ą░ąČą┤ąŠą╣ čüčéčĆąŠą║ąĄ ąĖąĘ ą▒ą░ąĘčŗ
  const validatedData = rawData.map((row: any) => {
    const item: any = {};
    
    idsKeys.forEach(({ key, validation }) => {
      // ąæąĄčĆąĄą╝ ąĘąĮą░čćąĄąĮąĖąĄ ąĖąĘ ą▒ą░ąĘčŗ (čāčćąĖčéčŗą▓ą░ąĄą╝, čćčéąŠ ą▓ ą▒ą░ąĘąĄ ą╝ąŠąČąĄčé ą▒čŗčéčī nameEN ąĖą╗ąĖ nameen)
      const rawValue = row[key] !== undefined ? row[key] : row[key.toLowerCase()];
      
      // ąĢčüą╗ąĖ ąĘąĮą░čćąĄąĮąĖčÅ ąĮąĄčé ą▓ąŠąŠą▒čēąĄ, ą┐ąŠą┤čüąŠą▓čŗą▓ą░ąĄą╝ ą┐čāčüčéčāčÄ čüčéčĆąŠą║čā ą┤ą╗čÅ ą▓ą░ą╗ąĖą┤ą░čéąŠčĆą░
      const valueToValidate = (rawValue === null || rawValue === undefined) ? "" : rawValue;

      // ąÆčŗąĘčŗą▓ą░ąĄą╝ čéą▓ąŠčÄ čäčāąĮą║čåąĖčÄ ą▓ą░ą╗ąĖą┤ą░čåąĖąĖ (ąĮą░ą┐čĆąĖą╝ąĄčĆ, validationToSinTypesArray)
      const { validatedVal, isValid } = validation(valueToValidate);

      if (isValid) {
        item[key] = validatedVal;
      } else {
        // ąĢčüą╗ąĖ ą▓ą░ą╗ąĖą┤ą░čåąĖčÅ ąĮąĄ ą┐čĆąŠčłą╗ą░, čüčéą░ą▓ąĖą╝ ą┤ąĄčäąŠą╗čé (ą┐čāčüčéąŠą╣ ą╝ą░čüčüąĖą▓ ąĖą╗ąĖ čüčéčĆąŠą║čā)
        // ą¦čéąŠą▒čŗ .map() ąĮąĄ ą║čĆą░čłąĖą╗ ą┐čĆąĖą╗ąŠąČąĄąĮąĖąĄ
        item[key] = Array.isArray(validatedVal) ? [] : validatedVal;
        console.warn(`Validation failed for key: ${key}, value: ${valueToValidate}`);
      }
    });

    return item;
  });

  console.log("Validated IDs Data:", validatedData);
  setDataToCache(validatedData);
  return validatedData;
};

export const useFetchIds = () => {
  return useQuery("identities", useFetchIdsAction, {
    staleTime: CACHE_TIME,
    cacheTime: Infinity,
    refetchOnWindowFocus: false,
    retry: 3,
  });
};

export const createQueryClient = () => {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { staleTime: CACHE_TIME, cacheTime: Infinity } }
  });
  if (typeof window !== 'undefined') {
    const cached = getDataFromCache();
    if (cached) queryClient.setQueryData("identities", cached);
  }
  return queryClient;
};