import React from 'react';
import { useTranslation } from 'react-i18next';
import { useQueryClient } from 'react-query';
import { useParams } from 'react-router-dom';
import { SEOHelmet } from '../../pages/SEOHelmet';
import { IdentityInterface } from '../../store/reducers/ids-reducer';
import { LanguageDisclaimer } from '../language-disclaimer/LanguageDisclaimer';
import { EntityFullInfoIdentity } from './entity-full-info-identity/EntityFullInfoIdentity';
import { EntityFullInfoSkills } from './entity-full-info-skills/EntityFullInfoSkills';
import "./EntityFullInfo.css"

export const EntityFullInfoIdentityMain = () => {
    const { identityId } = useParams();
    const { i18n, t } = useTranslation();
    const entities = useQueryClient().getQueryData('identities') as IdentityInterface[];
    const maxLvlIdentity = 60;
    const entity = entities.find(id => id.imgUrl === identityId);

    if (!entity) return null;

    const statusUnik = (entity as any).statusUnik || '';

    const nameKey = `name${i18n.language.toUpperCase()}` as keyof typeof entity;
    const rawName = entity[nameKey] as string;

    // ążąŠčĆą╝ą░čéąĖčĆčāąĄą╝ ID ą│čĆąĄčłąĮąĖą║ą░ ą┤ą╗čÅ ą┐ąĄčĆąĄą▓ąŠą┤ą░ (čāą▒ąĖčĆą░ąĄą╝ ą┐čĆąŠą▒ąĄą╗čŗ, ą▓ ąĮąĖąČąĮąĖą╣ čĆąĄą│ąĖčüčéčĆ)
    const sinnerId = (entity.sinner || "").toLowerCase().replace(/\s/g, "");
    const translatedSinner = t(`sinners.${sinnerId}`);

    // ąśčéąŠą│ąŠą▓ą░čÅ čüčéčĆąŠą║ą░: [ąØą░ąĘą▓ą░ąĮąĖąĄ] ąśą╝čÅ ąōčĆąĄčłąĮąĖą║ą░
    const fullDisplayName = `[${rawName}] ${translatedSinner}`;

    return (
        <>
            <SEOHelmet title={`${fullDisplayName} | Great Limbus Library`} description="" />
            <h1 className="entity-info-header">{fullDisplayName} <LanguageDisclaimer /></h1>
            <div className={"entityFullInfo"}>
                <EntityFullInfoIdentity identity={entity} maxLvlIdentity={maxLvlIdentity} statusUnik={statusUnik} />
                <EntityFullInfoSkills identity={entity} maxLvlIdentity={maxLvlIdentity} />
            </div>
        </>
    );
};