export const getUnbreakableCoinBonusFromDescription = (descriptions:string, countCoin:number) : boolean[] => {
  const unbreakableCoinBuff = new Array(countCoin).fill(false); // ąśąĮąĖčåąĖą░ą╗ąĖąĘąĖčĆčāąĄą╝ ą╝ą░čüčüąĖą▓

  const regex = /@(\d+)@\s*#unbreakableCoin#/g; // ąĀąĄą│čāą╗čÅčĆąĮąŠąĄ ą▓čŗčĆą░ąČąĄąĮąĖąĄ ą┤ą╗čÅ ą┐ąŠąĖčüą║ą░ ą▓čüąĄčģ ą▓čģąŠąČą┤ąĄąĮąĖą╣
  const matches = Array.from(descriptions.matchAll(regex)); // ą¤čĆąĄąŠą▒čĆą░ąĘčāąĄą╝ ąĖčéąĄčĆą░čéąŠčĆ ą▓ ą╝ą░čüčüąĖą▓

  for (const match of matches) {
    const index = parseInt(match[1], 10); // ąśąĘą▓ą╗ąĄą║ą░ąĄą╝ ąĘąĮą░čćąĄąĮąĖąĄ @x@
    
    // ą¤čĆąŠą▓ąĄčĆčÅąĄą╝, čćčéąŠ ąĖąĮą┤ąĄą║čü ą▓ą░ą╗ąĖą┤ąĄąĮ
    if (index >= 0 && index-1 < countCoin) {
      unbreakableCoinBuff[index-1] = true; // ąŻčüčéą░ąĮą░ą▓ą╗ąĖą▓ą░ąĄą╝ ąĘąĮą░čćąĄąĮąĖąĄ true ą▓ ąĮčāąČąĮčāčÄ čÅčćąĄą╣ą║čā
    }
  }

  return unbreakableCoinBuff;
}