import React, { useEffect, useRef } from "react";
import { useDispatch } from "react-redux";
import { sinType } from "../../../constants/types";
import useHover from "../../../../hooks/useHover";
import { useTypedSelector } from "../../../../hooks/useTypedSelector";
import { EGOInterface } from "../../../../store/reducers/ego-reducer";
import { SINNER_ORDER, SlotInterface, tbResetHoverAction, tbSetHoverAction, tbResetSlotAction, tbTriggerModalAction } from "../../../../store/reducers/tb-reducer";
import { getStatusesEntityList } from "../../../../tools/getStatusesEntityList";
import { IdentitySVG } from "../../../svg/IdentitySVG";

export const TbSlot: React.FC<{ slot: SlotInterface, index: number }> = ({ slot, index }) => {
    const dispatch = useDispatch();
    const tbHoverState = useTypedSelector(store => store.tbReducer.hover);

    const refSlot = useRef(null);
    const refSlotIdentity = useRef(null);
    const refSlotEGO = useRef(null);
    const assignedSinner = SINNER_ORDER[index];
    // ąĪą╗čāąČąĄą▒ąĮčŗąĄ čĆąĄčäčŗ ą┤ą╗čÅ ą║ąŠąĮą║čĆąĄčéąĮčŗčģ EGO
    const refZ = useRef(null); const refT = useRef(null); const refH = useRef(null);
    const refW = useRef(null); const refA = useRef(null);

    const isHoveringSlot = useHover(refSlot);
    const isHoveringId = useHover(refSlotIdentity);
    const isHoveringEgoArea = useHover(refSlotEGO);

    const { ego, identity } = slot;

    const egosMap = [
        { ego: ego.ZAYIN, ref: refZ, glyph: "ū¢" },
        { ego: ego.TETH,  ref: refT, glyph: "ūś" },
        { ego: ego.HE,    ref: refH, glyph: "ūö" },
        { ego: ego.WAW,   ref: refW, glyph: "ūĢ" },
        { ego: ego.ALEPH, ref: refA, glyph: "ŌäĄ" },
    ];

    // ą¤čĆąŠą▓ąĄčĆą║ą░, ąĮą░ą▓ąĄą┤ąĄąĮ ą╗ąĖ ą╝čŗčłčī ąĮą░ ą║ąŠąĮą║čĆąĄčéąĮčŗą╣ EGO ą▒ą╗ąŠą║
    const activeEgoIndex = [useHover(refZ), useHover(refT), useHover(refH), useHover(refW), useHover(refA)].indexOf(true);

    const tbEGOHoverMatch = (eObj: EGOInterface | null) => {
        if (!tbHoverState || !eObj) return false;
        if (tbHoverState.type === "sin") {
            return !!(eObj[tbHoverState.trigger as keyof EGOInterface]);
        } else if (tbHoverState.type === "tag") {
            const tags = getStatusesEntityList([eObj.descriptionCoinEN, eObj.descriptionPassiveEN]);
            return Object.keys(tags).includes(tbHoverState.trigger);
        }
        return false;
    };

    const tbIdentityHoverMatch = () => {
        if (!tbHoverState || !identity) return false;
        if (tbHoverState.type === "sin") {
            return identity.skillsSin.includes(tbHoverState.trigger as sinType);
        } else if (tbHoverState.type === "tag") {
            const tags = getStatusesEntityList([identity.descriptionCoinEN4, identity.descriptionPassive1EN, identity.descriptionPassive2EN]);
            return Object.keys(tags).includes(tbHoverState.trigger);
        }
        return false;
    };

    useEffect(() => {
        if (isHoveringId && identity) {
            tbSetHoverAction(dispatch, { type: "slot-identity", trigger: identity });
        } else if (activeEgoIndex !== -1 && egosMap[activeEgoIndex].ego) {
            tbSetHoverAction(dispatch, { type: "slot-ego", trigger: egosMap[activeEgoIndex].ego as EGOInterface });
        } else if (isHoveringSlot && !isHoveringId && !isHoveringEgoArea) {
            tbSetHoverAction(dispatch, { type: "slot", trigger: slot });
        }
        return () => { tbResetHoverAction(dispatch); };
    }, [isHoveringSlot, isHoveringId, isHoveringEgoArea, activeEgoIndex]);

    const isSlotEmpty = !identity && Object.values(ego).every(v => v === null);

    return (
        <div 
            ref={refSlot} 
            className={`tb-slots-slot ${isHoveringSlot && !isHoveringId && !isHoveringEgoArea && !isSlotEmpty ? "tb-slots-slot--active" : ""}`}
            onClick={() => tbTriggerModalAction(dispatch, slot)}
        >
            <div className="tb-slots-X" onClick={(e) => { e.stopPropagation(); tbResetSlotAction(dispatch, index); }}>&#10006;</div>
            <div className="tb-slots-tooltip">Click to edit</div>
            <div className="tb-slot-sinner-label">
                {assignedSinner.toUpperCase()}
            </div>
            <div 
                ref={refSlotIdentity} 
                className={`tb-slots-container-id ${tbIdentityHoverMatch() || (isHoveringId && identity) ? "tb-slots-container-id--active" : ""} ${!identity ? "tb-slots-empty" : ""}`}
            >
                <div className={identity ? "shadow" : ""}>
                    {!identity ? <IdentitySVG /> : <img src={`${process.env.PUBLIC_URL}/images/identities/${identity.imgUrl}.webp`} alt="id" />}
                </div>
            </div>

            <div ref={refSlotEGO} className="tb-slots-container-ego">
                {egosMap.map(({ ego: eObj, ref, glyph }, i) => (
                    <div 
                        ref={ref} 
                        key={i} 
                        className={`tb-slots-slot-ego ${tbEGOHoverMatch(eObj) || (activeEgoIndex === i && eObj) ? "tb-slots-slot-ego--active" : ""} ${!eObj ? "tb-slots-empty" : ""}`}
                    >
                        {!eObj ? (
                            <span>{glyph}</span>
                        ) : (
                            <>
                                <div className="shadow">
                                    <img src={`${process.env.PUBLIC_URL}/images/ego/${eObj.imgUrl}.webp`} alt="ego" />
                                </div>
                                <div className={`tb-ego-frame ${eObj.egoSin}-sin-color`} />
                            </>
                        )}
                    </div>
                ))}
            </div>
        </div>
    );
};