import React, { useEffect, useState, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { useQuery, QueryClient } from "react-query";
import { EventInterface } from "../../../store/reducers/events_list-reducer";
import { supabase, SUPABASE_URL, SUPABASE_ANON_KEY } from "../../../tools/supabaseClient"; 
import { eventsListKeys } from "../../../constants/eventsListKeys";
import "./EventsSection.css";

// --- ąŻčéąĖą╗ąĖčéčŗ ą┤ą╗čÅ ą┤ą░čé ---
const MSK_OFFSET = 3;
const getMskFixedDate = (dateStr: any, targetMskHour: number): Date | null => {
  if (!dateStr) return null;
  let date: Date;

  if (typeof dateStr === 'string' && /^\d{2}\.\d{2}\.\d{4}$/.test(dateStr)) {
    const [day, month, year] = dateStr.split('.').map(Number);
    const utcDate = Date.UTC(year, month - 1, day, targetMskHour - MSK_OFFSET, 0, 0);
    return new Date(utcDate);
  } else {
    date = new Date(dateStr);
    if (isNaN(date.getTime())) return null;
    date.setUTCHours(targetMskHour - MSK_OFFSET, 0, 0, 0);
  }
  return date;
};

// --- ąÜąŠą╝ą┐ąŠąĮąĄąĮčé ąŠčéą┤ąĄą╗čīąĮąŠą│ąŠ čüąŠą▒čŗčéąĖčÅ ---
const EventSector: React.FC<{ event: EventInterface; isAdmin: boolean }> = ({ event, isAdmin }) => {
  const { t, i18n } = useTranslation();
  const [now, setNow] = useState(new Date());
  
  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState<EventInterface>({ ...event });
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const { startDate, endDate } = useMemo(() => ({
    startDate: getMskFixedDate(event.startDate, 6),
    endDate: getMskFixedDate(event.endDate, 4),
  }), [event.startDate, event.endDate]);

  const handleUpdate = async () => {
    setIsSaving(true);
    
    // 1. ąōąŠčéąŠą▓ąĖą╝ ą┤ą░ąĮąĮčŗąĄ (ą┐ąŠą╝ąĮąĖą╝ ą┐čĆąŠ čĆąĄą│ąĖčüčéčĆ ą║ąŠą╗ąŠąĮąŠą║ ą▓ ą║ą░ą▓čŗčćą║ą░čģ)
    const updateData = {
      "startDate": editData.startDate,
      "endDate": editData.endDate,
      "nameRu": editData.nameRu,
      "nameEn": editData.nameEn,
      "link": editData.link,
      "imgSrc": editData.imgSrc
    };

    // 2. ą×čéą┐čĆą░ą▓ą╗čÅąĄą╝ (ąĖčüą┐ąŠą╗čīąĘčāąĄą╝ Number(id), čéą░ą║ ą║ą░ą║ ą╝čŗ čüą╝ąĄąĮąĖą╗ąĖ čéąĖą┐ ą▓ ąæąö ąĮą░ bigint)
    const { data, error } = await supabase
      .from('events')
      .update(updateData)
      .eq('id', Number(event.id))
      .select();

    if (error) {
      alert("ą×čłąĖą▒ą║ą░ ą┐čĆąĖ čüąŠčģčĆą░ąĮąĄąĮąĖąĖ: " + error.message);
    } else if (data && data.length > 0) {
      alert("ąÆčüąĄ ąĖąĘą╝ąĄąĮąĄąĮąĖčÅ čüąŠčģčĆą░ąĮąĄąĮčŗ!");
      
      // ą¦ąĖčüčéąĖą╝ ą║čŹčł, čćčéąŠą▒čŗ čüčĆą░ąĘčā čāą▓ąĖą┤ąĄčéčī čĆąĄąĘčāą╗čīčéą░čé
      localStorage.removeItem('events_list_cache');
      setIsEditing(false);
      
      // ą¤ąĄčĆąĄąĘą░ą│čĆčāąČą░ąĄą╝ čüčéčĆą░ąĮąĖčåčā čćąĄčĆąĄąĘ ą┐ąŠą╗čüąĄą║čāąĮą┤čŗ
      setTimeout(() => window.location.reload(), 500);
    } else {
      alert("ąĪčéčĆą░ąĮąĮąŠ: ą▒ą░ąĘą░ ąŠčéą▓ąĄčéąĖą╗ą░ čāčüą┐ąĄčģąŠą╝, ąĮąŠ ą┤ą░ąĮąĮčŗčģ ąĮąĄ ą▓ąĄčĆąĮčāą╗ą░. ą¤čĆąŠą▓ąĄčĆčī ID.");
    }
    
    setIsSaving(false);
  };

  const formatDiff = (ms: number) => {
    const d = Math.floor(ms / 86400000);
    const h = Math.floor((ms % 86400000) / 3600000);
    const m = Math.floor((ms % 3600000) / 60000);
    const s = Math.floor((ms % 60000) / 1000);
    return `${d}${t("EventsSection.d")} ${h}${t("EventsSection.h")} ${m}${t("EventsSection.m")} ${s}${t("EventsSection.s")}`;
  };

  const renderTimerContent = () => {
    if (!startDate) return <span>{t("EventsSection.startDateUnknown")}</span>;
    const diffStart = startDate.getTime() - now.getTime();
    if (diffStart > 0) return <>{t("EventsSection.eventStarts")}<br />{formatDiff(diffStart)}</>;
    if (!event.endDate || !endDate) return <span>{t("EventsSection.endDateUnknown")}</span>;
    const diffEnd = endDate.getTime() - now.getTime();
    if (diffEnd <= 0) return <span>{t("EventsSection.eventEnded")}</span>;
    return <>{t("EventsSection.eventEnds")}<br />{formatDiff(diffEnd)}</>;
  };

  if (isEditing && isAdmin) {
    return (
      <article className="event-sector editing-mode">
        <div className="edit-form-container">
          <input type="text" value={editData.nameRu ?? ""} onChange={e => setEditData({...editData, nameRu: e.target.value})} placeholder="ąØą░ąĘą▓ą░ąĮąĖąĄ RU" />
          <input type="text" value={editData.startDate ?? ""} onChange={e => setEditData({...editData, startDate: e.target.value})} placeholder="ąĪčéą░čĆčé DD.MM.YYYY" />
          <input type="text" value={editData.endDate ?? ""} onChange={e => setEditData({...editData, endDate: e.target.value})} placeholder="ąÜąŠąĮąĄčå DD.MM.YYYY" />
          <input type="text" value={editData.link ?? ""} onChange={e => setEditData({...editData, link: e.target.value})} placeholder="ąĪčüčŗą╗ą║ą░" />
          <input type="text" value={editData.imgSrc ?? ""} onChange={e => setEditData({...editData, imgSrc: e.target.value})} placeholder="URL ą║ą░čĆčéąĖąĮą║ąĖ" />
          <div className="edit-buttons">
            <button onClick={handleUpdate} disabled={isSaving}>{isSaving ? "..." : "ą×ąÜ"}</button>
            <button onClick={() => setIsEditing(false)}>X</button>
          </div>
        </div>
      </article>
    );
  }

  return (
    <article className="event-sector event-sector--animated">
      {isAdmin && <button className="edit-trigger-btn" onClick={() => setIsEditing(true)}>ŌÜÖ’ĖÅ</button>}
      <div className="event-timer">{renderTimerContent()}</div>
      <a href={event.link} target="_blank" rel="noopener noreferrer">
        <div className={i18n.language === "ru" ? "event-image-container-ru" : "event-image-container-en"}>
          <img src={event.imgSrc} alt={i18n.language === "ru" ? event.nameRu : event.nameEn} />
        </div>
      </a>
    </article>
  );
};

// --- ąøąŠą│ąĖą║ą░ ąĘą░ą│čĆčāąĘą║ąĖ ą┤ą░ąĮąĮčŗčģ ---
const CACHE_KEY = 'events_list_cache';
const CACHE_TIME = 15 * 60 * 1000;

const useFetchEventsListAction = async () => {
  const cached = localStorage.getItem(CACHE_KEY);
  if (cached) {
    const { data, timestamp } = JSON.parse(cached);
    if (Date.now() - timestamp < CACHE_TIME) return data;
  }

  const url = `${SUPABASE_URL}/rest/v1/events?select=*&apikey=${SUPABASE_ANON_KEY}`;
  const response = await fetch(url);
  if (!response.ok) throw new Error("ą×čłąĖą▒ą║ą░ ąĘą░ą│čĆčāąĘą║ąĖ");

  const rawData = await response.json();
  const validatedData = rawData.map((row: any) => {
    const item: any = {};
    eventsListKeys.forEach(({ key, validation }) => {
      const val = row[key] !== undefined ? row[key] : row[key.toLowerCase()];
      const { validatedVal } = validation(val ?? "");
      item[key] = validatedVal;
    });
    return item;
  });

  localStorage.setItem(CACHE_KEY, JSON.stringify({ data: validatedData, timestamp: Date.now() }));
  return validatedData;
};

export const useFetchEventsList = () => {
  return useQuery("events", useFetchEventsListAction, {
    staleTime: CACHE_TIME,
    refetchOnWindowFocus: false,
  });
};

// --- ąōąøąÉąÆąØą½ąÖ ąÜą×ą£ą¤ą×ąØąĢąØąó ---
export const EventsSection: React.FC = () => {
  const { data: events = [], isLoading } = useFetchEventsList();
  const { t } = useTranslation();
  const [isAdmin, setIsAdmin] = useState(false);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session) {
        supabase.from('profiles').select('is_admin').eq('id', session.user.id).single()
          .then(({ data }) => setIsAdmin(!!data?.is_admin));
      }
    });
  }, []);

  const sortedEvents = useMemo(() => {
    return [...events].sort((a, b) => Number(a.id) - Number(b.id));
  }, [events]);

  if (isLoading) return <div className="loading-shimmer">{t("EventsSection.loading")}</div>;

  return (
    <section className="events-section">
      <h2 className="new-entity">{t("EventsSection.header")}</h2>
      <div className="events-list-container">
        {sortedEvents.map((event, idx) => (
          <EventSector key={event.id || idx} event={event} isAdmin={isAdmin} />
        ))}
      </div>
    </section>
  );
};

// ąöą╗čÅ čüąŠą▓ą╝ąĄčüčéąĖą╝ąŠčüčéąĖ, ąĄčüą╗ąĖ ą│ą┤ąĄ-čéąŠ ąĖą╝ą┐ąŠčĆčé ą▒ąĄąĘ čäąĖą│čāčĆąĮčŗčģ čüą║ąŠą▒ąŠą║
export default EventsSection;