export const getAtackWeightBonusFromDescription = (descriptions: string[]): number => {
    let result: number = 0;
    
    descriptions.forEach(l => {
        if (!l) return;

        // ą×ą▒čĆą░ą▒ąŠčéą║ą░ Ōł×ą”ąĖčäčĆą░Ōł× (ą┤ąŠą▒ą░ą▓ą╗čÅąĄą╝ ą▒ąŠąĮčāčü ą▓ąĄčüą░ ąĖ čāą┤ą░ą╗čÅąĄą╝ ąĖąĘ ąŠą┐ąĖčüą░ąĮąĖčÅ)
        const infinityWeightMatches = l.match(/Ōł×(\d)Ōł×/g); // ąśąĘą╝ąĄąĮąĄąĮąŠ čü \d+ ąĮą░ \d
        if (infinityWeightMatches) {
            infinityWeightMatches.forEach(match => {
                const weight = parseInt(match.replace(/Ōł×/g, ''), 10);
                result += weight;
            });
        }

        // ą×čĆąĖą│ąĖąĮą░ą╗čīąĮą░čÅ ą╗ąŠą│ąĖą║ą░ ąŠą▒čĆą░ą▒ąŠčéą║ąĖ ?growth,maxCount?
        const current = l.replace(/Ōł×dŌł×/g, '').split("?"); // ąŻą┤ą░ą╗čÅąĄą╝ Ōł×ą”ąĖčäčĆą░Ōł× ą┐ąĄčĆąĄą┤ ąŠą▒čĆą░ą▒ąŠčéą║ąŠą╣
        for (let i = 1; i < current.length; i += 2) {
            const currTag = current[i];
            if (!currTag) continue;
            const [growth, maxCount] = currTag.split(",");
            const growthToNumber = Number(growth);
            const maxCountToNumber = Number(maxCount);
            result += (isNaN(growthToNumber) ? 0 : growthToNumber) * (isNaN(maxCountToNumber) ? 1 : maxCountToNumber);
        }
    });
    
    return result;
};

export const cleanDescriptionFromInfinityTags = (description: string): string => {
    return description.replace(/Ōł×dŌł×/g, '');
};