import React from 'react';
import "./EntityFullInfoSkill.css";
import { EGOInterface } from '../../../../store/reducers/ego-reducer';
import { SkillCoinDescription } from "../../../guides/text-formatter/SkillCoinDescription";
import { getAtackWeightBonusFromDescription } from '../../../../tools/getAtackWeightBonusFromDescription';
import { useTranslation } from 'react-i18next';
import { setMobileModalTrigger } from '../../../../store/reducers/mobile-modal-reducer';
import { mobileLayoutFrom } from '../../../../constants/mobileLayoutFrom';
import { useDispatch } from 'react-redux';
import { TooltipMobile } from '../../../tooltip-mobile/TooltipMobile';
import { getUnbreakableCoinBonusFromDescription } from '../../../../tools/getUnbreakableCoinBonusFromDescription';
import { ISkillEGO } from '../EntityFullInfoSkillsEGO';

interface IEntityFullInfoProps {
    ego: EGOInterface;
    skill: ISkillEGO;
    
}

export const EntityFullInfoSkillEGO: React.FC<IEntityFullInfoProps> = ({ ego, skill }) => {
    const { imgUrl, basicCoin, weightCoin, growthPerCoin, maxCoinValue, sanity, countCoin, clashCoinValue, damage } = ego;
    const { coins: coinsCount } = skill;
    const coins = new Array(coinsCount).fill(1);
    const { t, i18n } = useTranslation();
    const dispatch = useDispatch();

    const nameSkillKey = `nameSkill${i18n.language.toUpperCase()}` as keyof typeof ego;
    const nameSkill = ego[nameSkillKey] as string[];

    const descriptionCoinKey = `descriptionCoin${i18n.language.toUpperCase()}` as keyof typeof ego;
    const descriptionCoin = ego[descriptionCoinKey] as string;

    const descriptionPassiveKey = `descriptionPassive${i18n.language.toUpperCase()}` as keyof typeof ego;
    const descriptionPassive = ego[descriptionPassiveKey] as string;

    const parseSkillDescriptions = (desc: string) => {
        const result = {
            awakenings: [] as string[],
            corrosions: [] as string[]
        };

        if (!desc) return result;

        const cleanedDesc = desc.trim().replace(/^\|+|\|+$/g, '');

        if (cleanedDesc.includes("||")) {
            const parts = cleanedDesc.split("||").map(p => p.trim());
            
            if (parts[0]) {
                result.awakenings = parts[0].split("|")
                    .map(p => p.trim())
                    .filter(p => p.length > 0);
            }

            if (parts[1]) {
                result.corrosions = parts[1].split("|")
                    .map(p => p.trim())
                    .filter(p => p.length > 0);
            }
        } else if (cleanedDesc.includes("|")) {
            const parts = cleanedDesc.split("|").map(p => p.trim());
            if (parts[0]) result.awakenings = [parts[0]];
            if (parts[1]) result.corrosions = [parts[1]];
        } else {
            if (cleanedDesc) result.awakenings = [cleanedDesc];
        }

        return result;
    };

    const descriptions = parseSkillDescriptions(descriptionCoin);

    const handleMobileTooltipClick = (tooltip: React.ReactNode) => {
        if (window.innerWidth > mobileLayoutFrom) return;
        setMobileModalTrigger(dispatch, tooltip);
    };

    const getNameForSkill = (type: 'awakening' | 'corrosion', index: number) => {
        if (!nameSkill || nameSkill.length === 0) {
            return type === 'awakening' 
                ? t("EntityFullInfoSkillEGO.awakening") 
                : t("EntityFullInfoSkillEGO.corrosion");
        }

        const nameIndex = type === 'awakening' 
            ? index 
            : descriptions.awakenings.length + index;

        if (nameIndex < nameSkill.length) {
            return nameSkill[nameIndex];
        }

        return type === 'awakening' 
            ? t("EntityFullInfoSkillEGO.awakening") 
            : t("EntityFullInfoSkillEGO.corrosion");
    };

    const getParamValue = (param: number[], type: 'awakening' | 'corrosion', index: number) => {
        if (type === 'awakening') {
            return param[index] !== undefined ? param[index] : param[0];
        } else {
            const awakeningsCount = descriptions.awakenings.length;
            return param[awakeningsCount + index] !== undefined 
                ? param[awakeningsCount + index] 
                : param[param.length - 1];
        }
    };

    // ąØąŠą▓ą░čÅ čäčāąĮą║čåąĖčÅ ą┤ą╗čÅ ąŠą▒čĆą░ą▒ąŠčéą║ąĖ countCoin
    const getCoinCountValue = (type: 'awakening' | 'corrosion', index: number) => {
        if (!countCoin || countCoin.length === 0) return coinsCount;
        
        // ąĢčüą╗ąĖ ą║ąŠą╗ąĖčćąĄčüčéą▓ąŠ ąŠą┐ąĖčüą░ąĮąĖą╣ čüąŠą▓ą┐ą░ą┤ą░ąĄčé čü ą║ąŠą╗ąĖčćąĄčüčéą▓ąŠą╝ ąĘąĮą░čćąĄąĮąĖą╣ ą▓ countCoin
        const totalDescriptions = descriptions.awakenings.length + descriptions.corrosions.length;
        if (countCoin.length >= totalDescriptions) {
            if (type === 'awakening') {
                return countCoin[index] !== undefined ? countCoin[index] : countCoin[0];
            } else {
                const awakeningsCount = descriptions.awakenings.length;
                return countCoin[awakeningsCount + index] !== undefined 
                    ? countCoin[awakeningsCount + index] 
                    : countCoin[countCoin.length - 1];
            }
        }
        
        // ąĢčüą╗ąĖ ąĘąĮą░čćąĄąĮąĖą╣ ą╝ąĄąĮčīčłąĄ, čćąĄą╝ ąŠą┐ąĖčüą░ąĮąĖą╣, čĆą░čüą┐čĆąĄą┤ąĄą╗čÅąĄą╝ čåąĖą║ą╗ąĖčćąĄčüą║ąĖ
        const position = type === 'awakening' ? index : descriptions.awakenings.length + index;
        return countCoin[position % countCoin.length];
    };

    const renderSkillSection = (type: 'awakening' | 'corrosion', desc: string, index: number) => {
        const isCorrosion = type === 'corrosion';
        const skillIndex = isCorrosion ? descriptions.awakenings.length + index : index;
        
        const currentBasicCoin = getParamValue(basicCoin, type, index);
        const currentWeightCoin = getParamValue(weightCoin, type, index);
        const currentGrowthPerCoin = getParamValue(growthPerCoin, type, index);
        const currentMaxCoinValue = getParamValue(maxCoinValue, type, index);
        const currentSanity = getParamValue(sanity, type, index);
        const currentCountCoin = getCoinCountValue(type, index); // ą¤ąŠą╗čāčćą░ąĄą╝ ą┐čĆą░ą▓ąĖą╗čīąĮąŠąĄ ą║ąŠą╗ąĖčćąĄčüčéą▓ąŠ ą╝ąŠąĮąĄčéąŠą║
        const currentClashCoinValue = getParamValue(clashCoinValue, type, index);
        const currentDamage = getParamValue(damage, type, index);

        const attackWeightBuff = getAtackWeightBonusFromDescription([desc, descriptionPassive]);
        const coins = new Array(currentCountCoin).fill(1); // ąśčüą┐ąŠą╗čīąĘčāąĄą╝ currentCountCoin ą▓ą╝ąĄčüčéąŠ coinsCount
        const unbreakableCoinBuff = getUnbreakableCoinBonusFromDescription(desc, currentCountCoin);


        const damageGuardType = t("EntityFullInfoSkillEGO.damageType");
        const currentDmgType = skill.dmgType[type === 'awakening' ? 0 : 1] || skill.dmgType[0];
        const damageGuardTypeImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/${currentDmgType}.webp`} alt={`${currentDmgType}`} />;

        const sinType = t("EntityFullInfoSkillEGO.sin");
        const sinTypeImgHTML = <img src={`${process.env.PUBLIC_URL}/images/sins/${skill.sin}.webp`} alt={`${imgUrl}`} />;

        const maxCoinBaseValue = Math.sign(currentGrowthPerCoin) === -1
            ? currentBasicCoin
            : currentBasicCoin + currentGrowthPerCoin * currentCountCoin;

        const maxCoinTooltip = t("EntityFullInfoSkillEGO.maxCoin");
        const maxCoinImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/coinBefore.webp`} alt={`${imgUrl}`} />;

        const maxCoinWithConditionValue = currentMaxCoinValue;
        const clashCoinWithConditionValue = currentClashCoinValue;
        const maxCoinWithConditionTooltip = t("EntityFullInfoSkillEGO.coinCondition");
        const maxCoinWithConditionImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/coinCondition.webp`} alt={`${imgUrl}`} />;

        const baseDamageBonus = 60;
        const damageValue = Number(currentDamage) || 0;
        const attackDefLevelValue = damageValue + baseDamageBonus;
        const attackDefLevelTooltip = t("EntityFullInfoSkillEGO.offenseLevel");
        const attackDefLevelImgHTML = <img src={`${process.env.PUBLIC_URL}/images/general/damage.webp`} alt={`attack level`} />;

        return (
            <article key={`${type}-${index}`} className="entityFullInfo-skill">
                <div className="entityFullInfo-skill-r">
                    <div style={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: "20px", marginBottom: "15px" }}>
                        <p className={`skill-name ${skill.sin}-sin-color`}>
                            {getNameForSkill(type, index)}
                            {(descriptions[type === 'awakening' ? 'awakenings' : 'corrosions'].length > 1) && (
                                <span style={{ marginLeft: "5px" }}></span>
                            )}
                        </p>

                        <span onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.baseValue")} header={`${currentBasicCoin}`} />)}
                            className="skill-baseCoin tooltip-container coin-text">
                            {currentBasicCoin}
                            <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.baseValue")}</span>
                        </span>

                        <div className="entityFullInfo-coins">
                            <span onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.coinGain")} header={`${currentGrowthPerCoin}`} />)}
                                className="skill-coinGrowth tooltip-container">
                                {Math.sign(currentGrowthPerCoin) === -1 ? "" : "+"}{currentGrowthPerCoin}
                                <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.coinGain")}</span>
                            </span>

                            {coins.map((_, i) => (
                                !unbreakableCoinBuff[i] 
                                    ? <img key={i} src={`${process.env.PUBLIC_URL}/images/general/coin.webp`} alt="coin" /> 
                                    : <img key={i} src={`${process.env.PUBLIC_URL}/images/general/unbreakableCoin.webp`} alt="unbreakableCoin" />
                            ))}
                        </div>
                    </div>

                    <div style={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: "20px", marginBottom: "15px" }}>
                        <div onClick={() => handleMobileTooltipClick(<TooltipMobile text={damageGuardType} image={damageGuardTypeImgHTML} />)}
                            className="skill-atk tooltip-container">
                            {damageGuardTypeImgHTML}
                            <span className="entityFullInfo-tooltip">{damageGuardType}</span>
                        </div>

                        <div onClick={() => handleMobileTooltipClick(<TooltipMobile text={sinType} image={sinTypeImgHTML} />)}
                            className="skill-atk tooltip-container">
                            {sinTypeImgHTML}
                            <span className="entityFullInfo-tooltip">{sinType}</span>
                        </div>

                        <div onClick={() => handleMobileTooltipClick(<TooltipMobile text={attackDefLevelTooltip} header={`${attackDefLevelValue}`} image={attackDefLevelImgHTML} />)}
                            className="skill-atk tooltip-container">
                            {attackDefLevelValue}
                            {attackDefLevelImgHTML}
                            <span className="entityFullInfo-tooltip">{attackDefLevelTooltip}</span>
                        </div>

                        <div onClick={() => handleMobileTooltipClick(<TooltipMobile text={maxCoinTooltip} image={maxCoinImgHTML} header={`${maxCoinBaseValue}`} />)}
                            className="skill-atk tooltip-container">
                            {maxCoinBaseValue}
                            {maxCoinImgHTML}
                            <span className="entityFullInfo-tooltip">{maxCoinTooltip}</span>
                        </div>

                        <div onClick={() => handleMobileTooltipClick(<TooltipMobile text={maxCoinWithConditionTooltip} image={maxCoinWithConditionImgHTML} header={`${maxCoinWithConditionValue}`} />)}
                            className="skill-atk tooltip-container">
                            {maxCoinWithConditionValue}
                            {t('[')}{clashCoinWithConditionValue}{t(']')}
                            {maxCoinWithConditionImgHTML}
                            <span className="entityFullInfo-tooltip">{maxCoinWithConditionTooltip}</span>
                        </div>

                        <div style={{ textDecoration: "none" }} className="skill-weight">
                            <span onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.weightBase")} header={`${currentWeightCoin}`} />)}
                                style={{ display: "flex", flexDirection: "row", gap: "5px" }} className="tooltip-container">
                                {new Array(currentWeightCoin).fill(0).map((_, i) => <div key={i} />)}
                                <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.weightBase")}</span>
                            </span>

                            {attackWeightBuff !== 0 && (
                                <span onClick={() => handleMobileTooltipClick(<TooltipMobile text={t("EntityFullInfoSkillEGO.weight")} header={`${currentWeightCoin + attackWeightBuff}`} />)}
                                    style={{ textDecoration: "none", display: "flex", flexDirection: "row", gap: "5px" }} className="skill-weight skill-weight--buffed tooltip-container">
                                    <span>|</span>
                                    {new Array(currentWeightCoin + attackWeightBuff).fill(0).map((_, i) => <div key={i} />)}
                                    <span className="entityFullInfo-tooltip">{t("EntityFullInfoSkillEGO.weight")}</span>
                                </span>
                            )}
                        </div>
                    </div>
                    <SkillCoinDescription description={desc} />
                </div>
            </article>
        );
    };

    return (
        <>
            {descriptions.awakenings.map((desc, idx) => 
                renderSkillSection('awakening', desc, idx)
            )}
            
            {descriptions.corrosions.map((desc, idx) => 
                renderSkillSection('corrosion', desc, idx)
            )}
        </>
    );
};