import { useQuery, QueryClient } from "react-query";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../tools/supabaseClient";

// 1. ąÜąŠąĮčüčéą░ąĮčéčŗ ą║čŹčłąĖčĆąŠą▓ą░ąĮąĖčÅ
const CACHE_KEY = 'guides_supabase_cache';
const CACHE_TIME = 15 * 60 * 1000; // 35 ą╝ąĖąĮčāčé

// 2. ąŻčéąĖą╗ąĖčéčŗ ą║čŹčłą░
const getDataFromCache = () => {
  if (typeof window === 'undefined') return null;
  const cachedData = localStorage.getItem(CACHE_KEY);
  if (cachedData) {
    const { data, timestamp } = JSON.parse(cachedData);
    if (Date.now() - timestamp < CACHE_TIME) {
      return data;
    }
  }
  return null;
};

const setDataToCache = (data: any) => {
  const cacheData = {
    data,
    timestamp: Date.now(),
  };
  localStorage.setItem(CACHE_KEY, JSON.stringify(cacheData));
};

// 3. ąøąŠą│ąĖą║ą░ ąĘą░ą┐čĆąŠčüą░ ą║ Supabase
const useFetchGuidesAction = async () => {
  const cached = getDataFromCache();
  if (cached) return cached;

  // ąśčüą┐ąŠą╗čīąĘčāąĄą╝ ą▓ą░čłčā ąĮąŠą▓čāčÄ čéą░ą▒ą╗ąĖčåčā (čāą▒ąĄą┤ąĖčéąĄčüčī, čćčéąŠ ąĖą╝čÅ čüąŠą▓ą┐ą░ą┤ą░ąĄčé čü čéąĄą╝, čćčéąŠ ą▓ DBeaver)
  // ąöąŠą▒ą░ą▓ą╗čÅąĄą╝ order=ids.asc, čćčéąŠą▒čŗ ą┤ą░ąĮąĮčŗąĄ ą▓čüąĄą│ą┤ą░ čłą╗ąĖ ą▓ ą┐čĆą░ą▓ąĖą╗čīąĮąŠą╝ ą┐ąŠčĆčÅą┤ą║ąĄ
  const endpoint = '/rest/v1/guides?select=*&order=ids.asc';
  const url = `${SUPABASE_URL}${endpoint}&apikey=${SUPABASE_ANON_KEY}`;

  const response = await fetch(url, {
    method: 'GET',
    headers: {
      'Content-Type': 'application/json',
      'Prefer': 'return=representation' 
    }
  });

  if (!response.ok) {
    throw new Error(`ą×čłąĖą▒ą║ą░ Supabase: ${response.status}`);
  }

  const data = await response.json();
  setDataToCache(data);
  return data;
};

// 4. ą×čüąĮąŠą▓ąĮąŠą╣ čģčāą║ ą┤ą╗čÅ ą║ąŠą╝ą┐ąŠąĮąĄąĮčéąŠą▓
export const useFetchGuides = () => {
  return useQuery("guides", useFetchGuidesAction, {
    staleTime: CACHE_TIME,
    cacheTime: Infinity,
    refetchOnWindowFocus: false,
    retry: 8,
    retryDelay: (attempt) =>
      Math.min(attempt > 1 ? 2 ** attempt * 1000 : 1000, 30 * 1000),
    onError: (error) => {
      console.error("Error fetching guides from Supabase:", error);
    },
  });
};

// 5. ąĪąŠąĘą┤ą░ąĮąĖąĄ ą║ą╗ąĖąĄąĮčéą░ (ą┤ą╗čÅ ąĖčüą┐ąŠą╗čīąĘąŠą▓ą░ąĮąĖčÅ ą▓ App.tsx / _app.tsx)
export const createQueryClient = () => {
  const queryClient = new QueryClient({
    defaultOptions: {
      queries: {
        staleTime: CACHE_TIME,
        cacheTime: Infinity,
      },
    },
  });

  if (typeof window !== 'undefined') {
    const cachedData = getDataFromCache();
    if (cachedData) {
      queryClient.setQueryData("guides", cachedData);
    }
  }

  return queryClient;
};