import React, { useLayoutEffect, useRef, useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { Link, useLocation } from "react-router-dom";
import { locales } from "../../constants/locales";
import { mobileLayoutFrom } from "../../constants/mobileLayoutFrom";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { LanguageSelect } from "../language-select/LanguageSelect";
import { ContactSVG } from "../svg/ContactSVG";
import { EGOSVG } from "../svg/EGOSVG";
import { GLLSVG } from "../svg/GLLSVG";
import { GraditudeSVG } from "../svg/GraditudeSVG";
import { TurnamentSVG } from "../svg/TurnamentSVG";
import { IdentitiesSVG } from "../svg/IdentitiesSVG";
import { InfoSvg } from "../svg/InfoSVG";
import { StatusesPageSVG } from "../svg/StatusesPageSVG";
import { TeamBuilderSVG } from "../svg/TeamBuilderSVG";
import { TierListSVG } from "../svg/TierListSVG";
import { MirrorDungeonSVG } from "../svg/MirrorDungeonSVG";
import "./LeftMenu.css";
import { GuidesSVG } from "../svg/GuidesSVG";

export const LeftMenu: React.FC = () => {
    const location = useLocation();
    const { t, i18n } = useTranslation();
    const isMenuExpanded = useTypedSelector(store => store.leftMenuReducer);
    const [animationsDisabled, setAnimationsDisabled] = useState(() => {
        // ą¤ąŠą╗čāčćą░ąĄą╝ čüąŠčģčĆą░ąĮąĄąĮąĮąŠąĄ čüąŠčüčéąŠčÅąĮąĖąĄ ąĖąĘ localStorage ą┐čĆąĖ ąĖąĮąĖčåąĖą░ą╗ąĖąĘą░čåąĖąĖ
        const saved = localStorage.getItem('animationsDisabled');
        return saved === 'true';
    });

    const isCurrentLocation = (route: string) => {
        try {
            const splited = location.pathname.split("/");
            return splited[2].includes(route) && (splited.length === 3 || ["tierlist", "mirror-dungeon"].includes(route));
        } catch (err) {
            return false;
        }
    };

    // ąÆąĮčāčéčĆąĖ useEffect ą▓ LeftMenu.tsx
    useEffect(() => {
        const style = document.createElement('style');
        style.id = 'animation-disabler';
        
        if (animationsDisabled) {
            style.innerHTML = `
                * {
                    animation: none !important;
                    transition: none !important;
                }
                [class*="--animated"],
                .entity-section-bar,
                .entity-section-bar .entities-list,
                .entity-section-bar--animated .entities-list {
                    opacity: 1 !important;
                    transform: none !important;
                }
                .entity-section-bar .release-date hr {
                opacity: 1 !important;
                transform: none !important;
                width: 100% !important; /* ą¤čĆąĖąĮčāą┤ąĖčéąĄą╗čīąĮąŠ ąĘą░ą┤ą░čæą╝ čłąĖčĆąĖąĮčā ą┤ą╗čÅ hr */
                }   
                .item-entity-container .shadow {
                    /* ą×čüčéą░ą▓ą╗čÅąĄą╝ čéąĄąĮčī ą▓ąĖą┤ąĖą╝ąŠą╣ */
                    opacity: 1 !important;

                }
                .item-entity-container {
                    /* ą×čüčéą░ą▓ą╗čÅąĄą╝ čéąĄąĮčī ą▓ąĖą┤ąĖą╝ąŠą╣ */
                    opacity: 1 !important;

                }
            `;
            document.head.appendChild(style);
            
            // ą¤čĆąĖąĮčāą┤ąĖčéąĄą╗čīąĮąŠ ą┐ąŠą║ą░ąĘčŗą▓ą░ąĄą╝ ą▓čüąĄ čüą║čĆčŗčéčŗąĄ čŹą╗ąĄą╝ąĄąĮčéčŗ
            document.querySelectorAll('.entity-section-bar, .entities-list').forEach((el) => {
                const htmlEl = el as HTMLElement;
                htmlEl.style.opacity = '1';
                htmlEl.style.transform = 'none';
            });
        } else {
            const existingStyle = document.getElementById('animation-disabler');
            if (existingStyle) {
                document.head.removeChild(existingStyle);
            }
            
            // ąÆąŠčüčüčéą░ąĮą░ą▓ą╗ąĖą▓ą░ąĄą╝ ą░ąĮąĖą╝ą░čåąĖąĖ
            document.querySelectorAll('.entity-section-bar, .entities-list').forEach((el) => {
                const htmlEl = el as HTMLElement;
                htmlEl.style.opacity = '';
                htmlEl.style.transform = '';
            });
        }

        localStorage.setItem('animationsDisabled', String(animationsDisabled));

        return () => {
            const existingStyle = document.getElementById('animation-disabler');
            if (existingStyle) {
                document.head.removeChild(existingStyle);
            }
        };
    }, [animationsDisabled]);

    const navLang = locales.some(l => l.locale === i18n.language) ? i18n.language : "en";
    const links = [
        { to: `/limbus/${navLang}/graditude`, route: `graditude`, name: t('LeftMenu.graditude'), SVG: GraditudeSVG },
        { to: `/limbus/${navLang}/tierlist/identities`, route: `tierlist`, name: t('LeftMenu.tierlist'), SVG: TierListSVG },
        { to: `/limbus/${navLang}/teambuilder`, route: `teambuilder`, name: t('LeftMenu.teambuilder'), SVG: TeamBuilderSVG },
        { to: `/limbus/${navLang}/identities`, route: `identities`, name: t('LeftMenu.identities'), SVG: IdentitiesSVG },
        { to: `/limbus/${navLang}/ego`, route: `ego`, name: t('LeftMenu.ego'), SVG: EGOSVG },
        { to: `/limbus/${navLang}/guides`, route: `guides`, name: t('LeftMenu.guides'), SVG: GuidesSVG },
        { to: `/limbus/${navLang}/mirror-dungeon/events`, route: `mirror-dungeon`, name: t('LeftMenu.mirror_dungeon'), SVG: MirrorDungeonSVG },
        { to: `/limbus/${navLang}/statuses`, route: `statuses`, name: t('LeftMenu.statuses'), SVG: StatusesPageSVG },
        { to: `/limbus/${navLang}/aboutgame`, route: `aboutgame`, name: t('LeftMenu.aboutgame'), SVG: InfoSvg },
        { to: `/limbus/${navLang}/contact`, route: `contact`, name: t('LeftMenu.contact'), SVG: ContactSVG },
    ];

    const [hasRendered, setHasRendered] = useState(false);

    useLayoutEffect(() => {
        setHasRendered(true);
    }, []);

    const toggleAnimations = () => {
        setAnimationsDisabled(!animationsDisabled);
    };

    const ref = useRef<HTMLDivElement>(null);

    return (
        <div
            ref={ref}
            className={`left-menu ${hasRendered ? '' : 'first-render'} ${isMenuExpanded ? "left-menu--minimized" : "left-menu--maximized"}`}
            style={{
                transform: (isMenuExpanded && window.innerWidth <= mobileLayoutFrom) ? `translateX(-100%)` : `translateX(0)`
            }}
        >
            <nav>
                <ul>
                    <li>
                    <Link to={`/limbus/${navLang}/`}>
                        <GLLSVG /> <span>GREAT <span>LIMBUS</span> LIBRARY</span>
                    </Link>
                    </li>
                    {links.map(({ route, name, to, SVG }) => {
                        const isCurrentRouteLocation = isCurrentLocation(route);
                        return (
                            <li key={route}>
                                <Link
                                    onClick={(e) => {
                                        if (isCurrentRouteLocation) e.preventDefault();
                                    }}
                                    className={(isCurrentRouteLocation ? "left-menu-route--active" : "")}
                                    to={to}
                                >
                                    <SVG active={isCurrentRouteLocation} />
                                    {name}
                                </Link>
                            </li>
                        )
                    })}
                    <hr className="menu-separator" />
                    <li className="toggle-animations-container">
                    <div className="toggle-full-width-line"></div>
                    <button
                        onClick={toggleAnimations}
                        className={`toggle-animations-button ${animationsDisabled ? 'disabled' : ''}`}
                        aria-label={animationsDisabled ? t('LeftMenu.enableAnimations') : t('LeftMenu.disableAnimations')}
                    >
                        <span className="toggle-track">
                        <span className="toggle-thumb"></span>
                        </span>
                        
                        <span className="toggle-label">
                        {animationsDisabled ? t('LeftMenu.enableAnimations') : t('LeftMenu.disableAnimations')}
                        </span>
                    </button>
                    </li>
                    <hr className="menu-separator" />
                </ul>
            </nav>
            <LanguageSelect />
        </div>
    )
}