import React, { useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { useDispatch } from 'react-redux';
import { setMobileModalTrigger } from '../../../store/reducers/mobile-modal-reducer';
import { StatusesInterface } from '../../../store/reducers/statuses-reducer';
import { IdentityInterface } from '../../../store/reducers/ids-reducer';
import { EGOInterface } from '../../../store/reducers/ego-reducer';
import { MDGift } from '../../../store/reducers/md-gift-interface';
import { TooltipMobile } from '../../tooltip-mobile/TooltipMobile';
import "./SkillCoinDescription.css";
import { ItemEntity } from '../../item-entity/ItemEntity';
import "../../item-entity/ItemEntity.css"
import { mdSelectGiftIdAction } from '../../../store/reducers/md-reducer';
import { Link } from 'react-router-dom';
import { useQueryClient } from "react-query";
import { useIntersectionObserver } from '../../../hooks/useIntersectionObserver';
import { ArrowsRightNavigateSVG } from '../../svg/ArrowsRightNavigate';

interface ISkillCoinDescriptionProps {
    description: React.ReactNode;
    historyContext?: React.ReactNode[];
}

export const romanNumerals: Record<string, string> = {
    6: 'EX', 5: 'V', 4: 'IV', 3: 'III', 2: 'II', 1: 'I'
};


export const SkillCoinDescription: React.FC<ISkillCoinDescriptionProps> = ({ description, historyContext = [] }) => {
    const { t, i18n } = useTranslation();
    const dispatch = useDispatch();
    const queryClient = useQueryClient();

    const statuses = queryClient.getQueryData('statuses') as StatusesInterface[];
    const ids = queryClient.getQueryData('identities') as IdentityInterface[];
    const egos = queryClient.getQueryData('ego') as EGOInterface[];
    const gifts = queryClient.getQueryData("md-gifts") as MDGift[];

    // --- ąśąĮčéąĄą│čĆą░čåąĖčÅ ą╗ąŠą│ąĖą║ąĖ MDFormatedText ---
    const giftLinkFunc = (giftId: string) => {
        const gift = gifts?.find(g => g.id === giftId);
        if (!gift) return <span key={Math.random()}>#{giftId}#</span>;

        const name = i18n.language === "ru" ? gift.nameRU : gift.nameEN;
        
        return (
            <Link 
                className="MDFormatedText-link"
                to={`/limbus/${i18n.language}/mirror-dungeon/gifts`} 
                onClick={(e) => {
                    e.stopPropagation();
                    mdSelectGiftIdAction(dispatch, gift.id);
                }} 
                key={giftId + Math.random()}
            >
                <figure className="MDFormatedText-figure">
                    <img 
                        className='small-img'
                        src={`${process.env.PUBLIC_URL}/images/md-gifts/${gift.id}.webp`} 
                        alt={name}
                    />
                    <img 
                        className='big-img'
                        src={`${process.env.PUBLIC_URL}/images/md-gifts/${gift.id}.webp`} 
                        alt={name}
                    />
                    <figcaption className={`MDFormatedText--${(gift.id !== "gift_0") ? gift.sin : "none"}`}>
                        {name}
                    </figcaption>
                </figure>
            </Link>
        );
    };

    const tagFunc = (fullTagContent: string, resultLength: number) => {
        // ąĢčüą╗ąĖ čŹčéąŠ ID ą┐ąŠą┤ą░čĆą║ą░ (ąĮą░čćąĖąĮą░ąĄčéčüčÅ čü gift_)
        if (fullTagContent.startsWith('gift_')) {
            return giftLinkFunc(fullTagContent);
        }

        const match = fullTagContent.match(/^([^#{}]+)(?:\{([^}]*)\})?$/);
        if (!match) return null;

        const statusId = match[1];
        const customText = match[2];

        const status = statuses?.find((s) => s.id === statusId);
        if (!status) return <span key={Math.random()}>{fullTagContent}</span>;

        let name = i18n.language === "ru" ? status.nameRU : status.nameEN;
        if (i18n.language === "ru" && customText) name = customText;

        const descriptionStatus = i18n.language === "ru" ? status.descriptionRU : status.descriptionEN;
        const imgPath = `${process.env.PUBLIC_URL}/images/tags/${statusId}.webp`;

        const mobileModalHTML = (
            <TooltipMobile 
                image={<img className="status" src={imgPath} alt={statusId} />} 
                header={i18n.language === "ru" ? status.nameRU : status.nameEN} 
                text={descriptionStatus} 
                history={historyContext}
            />
        );

        let statusClass = status.tip === 'baf' ? 'status-name2' : status.tip === 'pas' ? 'status-name3' : 'status-name';

        return (
            <React.Fragment key={resultLength + Math.random()}>
                <img className="guide-status" src={imgPath} alt={statusId} style={{ width: "25px", height: "25px"}} />
                <span 
                    onClick={(e) => {
                        e.stopPropagation();
                        setMobileModalTrigger(dispatch, mobileModalHTML);
                    }} 
                    className={`${statusClass} status-name--${statusId} tooltip-container`}
                    style={{ cursor: 'pointer' }}
                >
                    {name}
                    <span className="entityFullInfo-tooltip">{t("SkillCoinDescription.clickToSeeDescription")}</span>
                </span>
            </React.Fragment>
        );
    };

    // --- ą×čüčéą░ą╗čīąĮčŗąĄ čäčāąĮą║čåąĖąĖ (redTextFunc, coinFunc ąĖ čé.ą┤.) ---
    const redTextFunc = (value: string) => <span key={Math.random()} className="red-text">{value}</span>;
    const yellowUnderlinedFunc = (value: string) => <span key={Math.random()} style={{ color: '#f1d34d', textDecoration: 'underline' }}>{value}</span>;
    const infinityWeightFunc = (value: string) => {
        // ąśąĘą▓ą╗ąĄą║ą░ąĄą╝ čéąŠą╗čīą║ąŠ čćąĖčüą╗ąŠ ąĖąĘ Ōł×5Ōł×, ąĄčüą╗ąĖ ąŠąĮąŠ čéą░ą╝ ąĄčüčéčī
        const weight = value.replace(/Ōł×/g, ''); 
        
        return (
            <span key={Math.random()} className="infinity-weight">
               
            </span>
        );
    };
    const simpleGiftFunc = (giftId: string, resultLength: number) => {
        const gift = gifts?.find(g => g.id === giftId);
        if (!gift) return <span key={Math.random()}>@{giftId}@</span>;

        const name = i18n.language === "ru" ? gift.nameRU : gift.nameEN;
        // ąśčüą┐ąŠą╗čīąĘčāąĄą╝ grade1RU / grade1EN ą▓ą╝ąĄčüčéąŠ ąĮąĄčüčāčēąĄčüčéą▓čāčÄčēąĖčģ descriptionRU / descriptionEN
        const descriptionGift = i18n.language === "ru" ? gift.grade1RU : gift.grade1EN;
        const imgPath = `${process.env.PUBLIC_URL}/images/md-gifts/${giftId}.webp`;

        const mobileModalHTML = (
            <TooltipMobile 
                image={<img className="status" src={imgPath} alt={giftId} />} 
                header={name} 
                text={descriptionGift} 
                history={historyContext}
            />
        );

        return (
            <React.Fragment key={resultLength + Math.random()}>
                <img className="guide-status" src={imgPath} alt={giftId} style={{ width: "25px", height: "25px"}} />
                <span 
                    onClick={(e) => {
                        e.stopPropagation();
                        setMobileModalTrigger(dispatch, mobileModalHTML);
                    }} 
                    className={`status-name status-name--gift tooltip-container`}
                    style={{ cursor: 'pointer' }}
                >
                    {name}
                    <span className="entityFullInfo-tooltip">{t("SkillCoinDescription.clickToSeeDescription")}</span>
                </span>
            </React.Fragment>
        );
    };
    const egoFunc = (value: string) => {
        const item = egos?.find(e => e.imgUrl === value) || ids?.find(i => i.imgUrl === value);
        if (!item) return null;
        return <span key={item.imgUrl} style={{ display: "inline-block" }}><ItemEntity entity={item} /></span>;
    };

    const newEntityLinkFunc = (fullMatch: string) => {
        const isEgos = fullMatch.startsWith('egos_');
        const idRaw = fullMatch.match(/\d+/)?.[0];
        const imgUrl = isEgos ? `ego_${idRaw}` : `id_${idRaw}`;
        
        const item = isEgos 
            ? egos?.find(e => e.imgUrl === imgUrl) 
            : ids?.find(i => i.imgUrl === imgUrl);
        
        if (!item) return fullMatch;

        // ąØą░ąĘą▓ą░ąĮąĖąĄ ą▓ ą║ą▓ą░ą┤čĆą░čéąĮčŗčģ čüą║ąŠą▒ą║ą░čģ [Name]
        const baseName = i18n.language === 'ru' ? item.nameRU : item.nameEN;
        
        // ą×ą¦ąśąĪąóąÜąÉ ąÜąøą«ą¦ąÉ: čāą▒ąĖčĆą░ąĄą╝ ą┐čĆąŠą▒ąĄą╗čŗ ąĖąĘ sinner (ąĮą░ą┐čĆąĖą╝ąĄčĆ, "don quixote" -> "donquixote")
        const sinnerKey = item.sinner?.toLowerCase().replace(/\s+/g, '');
        
        // ąæąĄčĆąĄą╝ ą┐ąĄčĆąĄą▓ąŠą┤ ąĖąĘ i18n ą┐ąŠ čćąĖčüčéąŠą╝čā ą║ą╗čÄčćčā
        const translatedSinner = t(`sinners.${sinnerKey}`);

        // ąĪą║ą╗ąĄąĖą▓ą░ąĄą╝ ą▒ąĄąĘ ą┐čĆąŠą▒ąĄą╗ą░: [Name]Sinner
        const name = `[${baseName}] ${translatedSinner}`;

        const path = isEgos ? 'ego' : 'identities';
        
        return (
            <Link key={imgUrl} to={`/limbus/${i18n.language}/${path}/${imgUrl}`} className="entity-link">
                <img className="entity-icon" src={`${process.env.PUBLIC_URL}/images/${path}/${imgUrl}.webp`} alt={imgUrl} />
                {name}
            </Link>
        );
    };

    const linkFunc = (value: string) => {
        const [text, link] = value.split(":");
        return <NavLink key={text} to={link} text={text} />;
    };

    const NavLink: React.FC<{ to: string, text: string }> = ({ to, text }) => {
        const containerRef = useRef(null);
        const { isVisible } = useIntersectionObserver(containerRef, 0.1)
        return <Link to={to} ref={containerRef} className={`nav-link ${isVisible && "nav-link--animated"}`}>{text} <ArrowsRightNavigateSVG /></Link>
    };

    const coinFunc = (value: string, result: React.ReactNode[]) => {
        if (isNaN(+value)) return value;
        return (
            <React.Fragment key={result.length + Math.random()}>
                {!!result.length && <br />}
                <img className="coin" src={`${process.env.PUBLIC_URL}/images/general/coin${value}.webp`} alt="coin" />
            </React.Fragment>
        );
    };

    const conditionFunc = (value: string, result: React.ReactNode[], tracked: { lastCoinResultIndex: number }) => {
        const key = value.toLowerCase().replace(/\s/g, ''); // ą¤čĆąĖą▓ąŠą┤ąĖą╝ ą║ ą▓ąĖą┤čā [onhit]
        const isCloseToCoin = tracked.lastCoinResultIndex !== -1 && tracked.lastCoinResultIndex === result.length - 1;

        // ą¤čŗčéą░ąĄą╝čüčÅ ą┐ąŠą╗čāčćąĖčéčī ą┐ąĄčĆąĄą▓ąŠą┤ ąĖąĘ čüąĄą║čåąĖąĖ SkillCoinDescription
        const translatedLabel = t(`SkillCoinDescription.${key}`);

        // ąĢčüą╗ąĖ ą┐ąĄčĆąĄą▓ąŠą┤ ąĮąĄ ąĮą░ą╣ą┤ąĄąĮ, i18next ą▓ąĄčĆąĮąĄčé ą┐čāčéčī ą║ ą║ą╗čÄčćčā. 
        // ą¤čĆąŠą▓ąĄčĆčÅąĄą╝, čćčéąŠ čĆąĄąĘčāą╗čīčéą░čé ą┐ąĄčĆąĄą▓ąŠą┤ą░ ąĮąĄ čĆą░ą▓ąĄąĮ čüą░ą╝ąŠą╝čā ą┐čāčéąĖ (ąĘąĮą░čćąĖčé ą┐ąĄčĆąĄą▓ąŠą┤ ąĄčüčéčī)
        const hasTranslation = translatedLabel !== `SkillCoinDescription.${key}`;

        return (
            <React.Fragment key={result.length + Math.random()}>
                {(!isCloseToCoin && !!result.length) && <br />}
                <span className={`condition condition--${key.substring(1, key.length - 1)}`}>
                    {hasTranslation ? translatedLabel : value} 
                </span>
            </React.Fragment>
        );
    };

    const coinsConditionsFunc = (value: string, result: React.ReactNode[]) => {
        let keyVal = ""; let numberVal = "";
        for (let char of value) {
            if (isNaN(+char) && !["-", "+"].includes(char)) keyVal += char;
            else if (char !== " ") numberVal += char;
        }
        return <span key={result.length + Math.random()} className={`coins-coditions coins-coditions--${keyVal.toLowerCase()}`}>{numberVal} {t(`SkillCoinDescription.${keyVal.toLowerCase()}`)}</span>;
    };

    const weightFunc = (value: string) => {
        // ąĪą╗čāčćą░ą╣ ??
        if (!value || value.trim() === "") {
            return <span className="description-weight" key={Math.random()}>{t("SkillCoinDescription.weigth")}</span>;
        }

        const [growth, max] = value.split(",");
        
        // ąĢčüą╗ąĖ ąĮą░ą┐ąĖčüą░ą╗ąĖ ?,5?, čéąŠ growth ą▒čāą┤ąĄčé ą┐čāčüčéąŠą╣ čüčéčĆąŠą║ąŠą╣.
        // ą¤čĆąŠą▓ąĄčĆčÅąĄą╝, ąĄčüčéčī ą╗ąĖ čéą░ą╝ ą▓ąŠąŠą▒čēąĄ čüąĖą╝ą▓ąŠą╗čŗ čåąĖčäčĆ.
        const hasGrowth = growth && growth.trim().length > 0;
        const numGrowth = hasGrowth ? +growth : null;

        return (
            <span className="description-weight" key={Math.random()}>
                {/* ąĢčüą╗ąĖ čåąĖčäčĆą░ ąĄčüčéčī, čĆąĖčüčāąĄą╝ ąĄčæ čü ą┐ą╗čÄčüąŠą╝. ąĢčüą╗ąĖ ąĮąĄčé (ą║ą░ą║ ą▓ ?,5?), ąĮąĖčćąĄą│ąŠ ąĮąĄ čĆąĖčüčāąĄą╝ */}
                {hasGrowth && (numGrowth! > 0 ? `+${numGrowth} ` : `${numGrowth} `)}
                
                {/* ąĢčüą╗ąĖ čŹčéąŠ čüą╗čāčćą░ą╣ ?,5? - ą┤ąŠą▒ą░ą▓ą╗čÅąĄą╝ + ą┐ąĄčĆąĄą┤ čéąĄą║čüčéąŠą╝ "ąÆąĄčü ą░čéą░ą║ąĖ" */}
                {!hasGrowth && max ? "" : ""}
                
                {t("SkillCoinDescription.weigth")}
                {max ? ` (${t("SkillCoinDescription.max")} ${max})` : ""}
            </span>
        );
    };

    const stSpecialsMap: Record<string, any> = { "@": coinFunc, "$": conditionFunc, "?": weightFunc, "&": coinsConditionsFunc };

    const processStContent = (content: string, resultLength: number) => {
        let tracked = { value: "", index: -1, lastCoinResultIndex: -1 };
        let res: React.ReactNode[] = [];
        const stSpecialsMap: Record<string, any> = { "@": coinFunc, "$": conditionFunc, "?": weightFunc, "&": coinsConditionsFunc };

        for (let i = 0; i < content.length; i++) {
            const char = content[i];
            if (char in stSpecialsMap) {
                if (char === tracked.value) {
                    const val = content.substring(tracked.index + 1, i);
                    
                    // ąĢčüą╗ąĖ čŹčéąŠ @ ąĖ čŹčéąŠ ą┐ąŠą┤ą░čĆąŠą║ ŌĆö ą▓čŗąĘčŗą▓ą░ąĄą╝ ą┐čĆąŠčüčéčāčÄ ąĖą║ąŠąĮą║čā
                    if (char === "@" && val.startsWith('gift_')) {
                        res.push(simpleGiftFunc(val, res.length));
                    } else {
                        if (char === "@") tracked.lastCoinResultIndex = res.length;
                        res.push(stSpecialsMap[char](val, res, { lastCoinResultIndex: tracked.lastCoinResultIndex }));
                    }
                    
                    tracked = { ...tracked, value: "", index: i };
                } else {
                    const text = content.substring(tracked.index + 1, i);
                    if (tracked.value !== "@" && text !== "") res.push(<span key={res.length} dangerouslySetInnerHTML={{ __html: text.replaceAll("%", `<span class="perCent-special-font">%</span>`) }} />);
                    tracked = { ...tracked, value: char, index: i };
                }
            }
        }
        const remaining = content.substring(tracked.index + 1);
        if (remaining !== "") res.push(<span key={res.length} dangerouslySetInnerHTML={{ __html: remaining.replaceAll("%", `<span class="perCent-special-font">%</span>`) }} />);
        return <span className="st-content" key={`st-${resultLength}`}>{res}</span>;
    };

    const createDescriptionDangerousHTML = (str: React.ReactNode) => {
        if (!str || typeof str !== 'string') return str;

        // ąÆą░ąČąĮąŠ: \?[^\?]*\? (ąĘą▓ąĄąĘą┤ąŠčćą║ą░ ą▓ą╝ąĄčüčéąŠ ą┐ą╗čÄčüą░)
        const regex = /(#[^#\s{}]+(?:\{[^}]*\})?#)|(&(?:ids|egos)_\d+&)|(&[^&]+&)|(@[^@]+@)|(~[^~]+~)|(<e>(.*?)<\/e>)|(\*\*\+\*\*|\*\*\-\*\*|\*\*\+\-\*\*)|(\^[^\^]+\^)|(Ō£×[^Ō£×]+Ō£×)|(Ōł×[^Ōł×]+Ōł×)|(\?[^\?]*\?)|(\$[^\$]+\$)/g;
        let result: React.ReactNode[] = [];
        let lastIndex = 0;
        let match: RegExpExecArray | null;
        let lastCoinResultIndex = -1;

        while ((match = regex.exec(str)) !== null) {
            if (match.index > lastIndex) {
                const plain = str.slice(lastIndex, match.index);
                result.push(<span key={`plain-${lastIndex}`} dangerouslySetInnerHTML={{ __html: plain.replaceAll("%", `<span class="perCent-special-font">%</span>`) }} />);
            }

            const [full, tag, entityLink, coinsCond, coin, link, eFull, eInner, largeSymbol, red, yellow, infWeight, weight, condition] = match;

            if (tag) {
                // # ą▓čüąĄą│ą┤ą░ ąĖą┤ąĄčé ą▓ tagFunc (čéą░ą╝ ą▓ąĮčāčéčĆąĖ giftLinkFunc čüą┤ąĄą╗ą░ąĄčé čäąĖą│čāčĆčā)
                result.push(tagFunc(tag.slice(1, -1), result.length));
            } 
            else if (coin) {
                const content = coin.slice(1, -1);
                // ą¤ąĀą»ą£ąÉą» ą¤ąĀą×ąÆąĢąĀąÜąÉ ąöąøą» @
                if (content.startsWith('gift_')) {
                    // ąöą╗čÅ @ ąĖčüą┐ąŠą╗čīąĘčāąĄą╝ ą┐čĆąŠčüčéčāčÄ ąĖą║ąŠąĮą║čā
                    result.push(simpleGiftFunc(content, result.length));
                } else {
                    lastCoinResultIndex = result.length;
                    result.push(coinFunc(content, result));
                }
            }
            else if (eInner) result.push(processStContent(eInner, result.length));
            else if (entityLink) result.push(newEntityLinkFunc(entityLink.slice(1, -1)));
            else if (coinsCond) {
                const val = coinsCond.slice(1, -1);
                if (val.startsWith('id_') || val.startsWith('ego_')) result.push(egoFunc(val));
                else result.push(coinsConditionsFunc(val, result));
            }
            else if (link) result.push(linkFunc(link.slice(1, -1)));
            else if (largeSymbol) {
                const type = largeSymbol.includes('+-') ? 'plusminus' : largeSymbol.includes('+') ? 'plus' : 'minus';
                result.push(<span key={Math.random()} className={`large-symbol large-symbol--${type}`}>{largeSymbol.slice(2, -2)}</span>);
            }
            else if (red) result.push(redTextFunc(red.slice(1, -1)));
            else if (yellow) result.push(yellowUnderlinedFunc(yellow.slice(1, -1)));
            else if (infWeight) result.push(infinityWeightFunc(infWeight.slice(1, -1)));
            else if (weight) result.push(weightFunc(weight.slice(1, -1)));
            else if (condition) result.push(conditionFunc(condition.slice(1, -1), result, { lastCoinResultIndex }));

            lastIndex = regex.lastIndex;
        }

        if (lastIndex < str.length) {
            result.push(<span key={`rem-${lastIndex}`} dangerouslySetInnerHTML={{ __html: str.slice(lastIndex).replaceAll("%", `<span class="perCent-special-font">%</span>`) }} />);
        }
        return result;
    };

    return (
        <p className={`skill-coin-description`}>
            {createDescriptionDangerousHTML(description)}
        </p>
    );
};