// App.tsx
import React, { useEffect, useState } from 'react';
import './App.css';
import { AppRouter } from './componentslimbus/AppRouter';
import { UmamusumeRouter } from './componentsumamusume/UmamusumeRouter';
import { GameSelectionPage } from './GameSelectionPage';
import { store } from './store/store';
import { Provider } from 'react-redux';
import { BrowserRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from "react-query";
import { HelmetProvider } from 'react-helmet-async';
import './i18n';

const queryClient = new QueryClient();

const OldUrlRedirect = () => {
  const location = useLocation();
  const path = location.pathname;
  
  // ą¤čĆąŠą▓ąĄčĆčÅąĄą╝, ąĮą░čćąĖąĮą░ąĄčéčüčÅ ą╗ąĖ ą┐čāčéčī čü /limbus ąĖą╗ąĖ /umamusume
  if (path.startsWith('/limbus') || path.startsWith('/umamusume')) {
    return <Navigate to={`${path}${location.search}`} replace />;
  }
  
  // ąśąĮą░čćąĄ ą┤ąŠą▒ą░ą▓ą╗čÅąĄą╝ /limbus
  return <Navigate to={`/limbus${path}${location.search}`} replace />;
};

// ąÜąŠą╝ą┐ąŠąĮąĄąĮčé ą║ąĮąŠą┐ą║ąĖ ąŠčćąĖčüčéą║ąĖ ą║čŹčłą░
const ClearCacheButton = () => {
  const clearCacheAndRefresh = () => {
    localStorage.clear();
    sessionStorage.clear();
    window.location.replace(
      window.location.origin +
      window.location.pathname +
      '?nocache=' +
      Date.now()
    );
  };

  return (
    <button
      className="clear-cache-button"
      onClick={clearCacheAndRefresh}
      title="ą×čćąĖčüčéąĖčéčī ą║čŹčł ąĖ ą┐ąĄčĆąĄąĘą░ą│čĆčāąĘąĖčéčī (Ctrl+Shift)"
    >
      Clear cache 
    </button>
  );
};

function App() {
  const [showButton, setShowButton] = useState(true);

  useEffect(() => {
    const clearCacheAndRefresh = () => {
      localStorage.clear();
      sessionStorage.clear();
      window.location.replace(
        window.location.origin +
        window.location.pathname +
        '?nocache=' +
        Date.now()
      );
    };

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.ctrlKey && e.shiftKey) {
        e.preventDefault();
        clearCacheAndRefresh();
      }
    };

    window.addEventListener('keydown', handleKeyDown);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, []);

  return (
    <HelmetProvider>
      <QueryClientProvider client={queryClient}>
        <Provider store={store}>
          <BrowserRouter>
            {showButton && <ClearCacheButton />}
            <Routes>
              {/* 1. ąĢčüą╗ąĖ ąĘą░čłą╗ąĖ ąĮą░ čćąĖčüčéčŗą╣ ą┤ąŠą╝ąĄąĮ gll-fun.com, ą║ąĖą┤ą░ąĄą╝ ąĮą░ ą│ą╗ą░ą▓ąĮčāčÄ ąøąĖą╝ą▒čāčüą░ */}
              <Route path="/" element={<Navigate to="/limbus/en/" replace />} />

              {/* 2. ąĪąĄą║čĆąĄčéąĮčŗą╣ ą┐čāčéčī ą┤ą╗čÅ ą▓čŗą▒ąŠčĆą░ ąĖą│čĆ (čéąĄčüčéąŠą▓čŗą╣ ą▓ą░čĆąĖą░ąĮčé) */}
              {/* ąóąĄą┐ąĄčĆčī ą┐ąŠą┐ą░čüčéčī ąĮą░ ą▓čŗą▒ąŠčĆ ąĖą│čĆ ą╝ąŠąČąĮąŠ čéąŠą╗čīą║ąŠ ą▓ą▓ąĄą┤čÅ /select-game ą▓čĆčāčćąĮčāčÄ */}
              <Route path="/select-game" element={<GameSelectionPage />} />

              {/* 3. ąĀą░ą▒ąŠčćąĖąĄ ą▓ąĄčéą║ąĖ ąĖą│čĆ */}
              <Route path="/limbus/*" element={<AppRouter />} />
              <Route path="/umamusume/*" element={<UmamusumeRouter />} />

              {/* 4. ąōą╗ąŠą▒ą░ą╗čīąĮčŗą╣ ą┐ąĄčĆąĄčģą▓ą░čéčćąĖą║: ąĄčüą╗ąĖ ą▓ ąĮą░čćą░ą╗ąĄ ąĮąĄčé /limbus/ ąĖą╗ąĖ /umamusume/, 
                   ąĘąĮą░čćąĖčé čŹčéąŠ čüčéą░čĆą░čÅ čüčüčŗą╗ą║ą░. ąÜąĖą┤ą░ąĄą╝ ąĄčæ ąĮą░ /limbus/ */}
              <Route path="*" element={<OldUrlRedirect />} />
            </Routes>
          </BrowserRouter>
        </Provider>
      </QueryClientProvider>
    </HelmetProvider>
  );
}

export default App;